(window.courseContentFiles = window.courseContentFiles || {})["000003/0008"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1><span style=\"color: rgb(88, 129, 87); font-weight: 600; text-align: center\"></span></h1><h1 style=\"text-align: center\">Тема 39. Възпалителни заболявания на устната кухина – видове. Реактивни мекотъканни и преканцерозни лезии на устната кухина.</h1><h2>Стоматит (Stomatitis)</h2><p><strong>Определение:</strong> Остро или хронично заболяване на лигавицата на устната кухина.</p><h3>Етиология</h3><p>Възникването му се свързва с въздействието на:</p><ul><li><strong>Механични фактори:</strong> кариес на зъбите.</li><li><strong>Химични фактори:</strong> тютюн, алкохол, пластмаси, протези, тежки метали (олово, бисмут и др.).</li><li><strong>Бактериални фактори:</strong> стафилококи, стрептококи, <em>Corynebacterium diphteriae</em>.</li><li><strong>Вирусни фактори:</strong> <em>herpes simplex</em>, <em>herpes zoster</em>.</li><li><strong>Микозни фактори:</strong> монилиаза, актиномикоза и др.</li><li><strong>Други:</strong> алергични фактори.</li></ul><h3>Неспецифични стоматити</h3><h4>Катарален и Везикулозен стоматит</h4><ul><li><strong>Макроскопски:</strong> Зачервена и набъбнала лигавица, покрита със слузен секрет.</li><li><strong>Микроскопски:</strong> <p> По повърхността на лигавицата </p><p>се установява </p>слузен ексудат с излющени епителни клетки. В спинозния слой се наблюдава <strong>вакуолизация</strong> на клетките. Възпалителният ексудат разкъсва свързващите мостчета между клетките, което води до загиването им и образуване на кухини (<strong>мехурчета</strong>), изпълнени със серозен ексудат. <p>По този начин се образуват </p><p>мехурчета, които могат да се открият по лигавица</p><p>та на бузите, устните, върха и ръбовете на езика. </p>Това е същността на <strong>везикулозния стоматит</strong>. <p>Пукнатите везикули могат да образуват язвички, които или епителизират, или се инфектират в гноен (пустулозен) стоматит.</p></li></ul><h4>Фибринозен стоматит</h4><ul><li><strong>Повърхностен (крупозен):</strong> Лигавицата е покрита с дебел фибринов налеп с некротични епителни клетки и левкоцити.</li><li><strong>Дълбок (дифтериен):</strong> Мръсно сиво-белезникави налепи, които се снемат трудно. Под тях се разкриват <strong>дълбоки язви</strong>. Наблюдава се некроза на епителните клетки и разрехавяване на спинозния слой.</li></ul><h4>Афтозен и Язвен стоматит</h4><ul><li><strong>Афтозен:</strong> Характеризира се с дребнопетнисти налепи (<strong>афти</strong>), обградени от хиперемичен вал. Могат да се усложнят с язви. </li><li><strong>Язвен:</strong> Язвите (3-4 mm) са разположени най-често близо до зъбите. В дъното им се откриват фибрин, детрит и левкоцити.</li></ul><h4>Гангренозен стоматит и Нома</h4><ul><li><strong>Гангренозен:</strong> Рядка форма с мръсносиво-зелена некроза на лигавицата, челюстите и зъбния апарат. Липсва защитна възпалителна реакция в здравата тъкан.</li><li><strong>Нома (noma):</strong> Гангренозно възпаление при деца (след морбили, скарлатина, коремен тиф). Започва като катарален или фибринозен, но завършва с обширна гангрена.</li></ul><h3>Специфични стоматити</h3><ul><li><strong>Микотичен:</strong> Най-често монилиаза (<strong>soor</strong>), причинена от <em>Candida albicans</em>.</li><li><strong>Токсични:</strong> Свързани с професионални фактори — олово (полиграфия) и живак (мини).</li><li><strong>Други:</strong> Туберкулозен и луетичен (сифилистичен).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Глосит (Glossitis)</h1><p><strong>Определение:</strong> Възпалителен процес на езика (първичен или вторичен).</p><h3>Остър глосит</h3><ul><li><strong>Етиология:</strong> Механични, физични (гореща храна), химични и биологични (бактерии и вируси) фактори.</li><li><strong>Катарален:</strong> Езикът е оточен и червен. Микроскопски има десквамация на епитела и инфилтрат от лимфоцити и плазмоцити. Среща се при морбили, скарлатина, коремен тиф.</li><li><strong>Географски език (lingua geographica):</strong> Рядка форма на фибринозен глосит при деца и изтощени болни. Виждат се сиво-белезникави плаки, които се сливат и по-късно се десквамират, създавайки петнист вид.</li><li><strong>Соор (Soor):</strong> Микотичен глосит (<em>Candida albicans</em>).</li></ul><h3>Хроничен (Атрофичен) глосит</h3><p>Това е най-характерната хронична форма.</p><ul><li><strong>Макроскопски:</strong> Папилите атрофират и езикът става блестящочервен — <strong>полиран език</strong>.</li><li><strong>Етиология:</strong> Наблюдава се при желязодефицитни анемии, пернициозна анемия и шпру.</li><li><strong>Микроскопски:</strong> Атрофия на многослойния епител и фибропластична реакция.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Ангина (Angina)</h1><p><strong>Определение:</strong> Първично или вторично възпаление на тонзилите, глътката и лигавицата на устната кухина. Тъй като основният процес е в сливиците, често се използва като синоним на <strong>тонзилит</strong>.</p><p><strong>Етиология:</strong> Причинява се от механични, физични, химични и биологични (бактерии и вируси) фактори.</p><h2>Остра ангина</h2><h3>Катарална и фоликуларна ангина</h3><ul><li><strong>Катарална:</strong> </li><ul><li><strong>Макроскопски</strong>: Тонзилите са увеличени, зачервени и сочни, обложени с мътен слузен секрет, който изтича при притискане. </li><li><strong>Микроскопски</strong>: Наблюдава се оток, хиперемия и хиперплазия на лимфоидния апарат.</li></ul><li><strong>Фоликуларна:</strong> Вариант, при който доминира хиперплазията на лимфните фоликули.</li></ul><h3>Фибринозна ангина</h3><ol><li><strong>Повърхностна:</strong> </li><ul><li><strong>Етиология</strong>: Среща се при грип, скарлатина или простуда, или въздействие на различни химични фактори.</li><li><strong>Макроскопски</strong>: Тонзилите и небните дъги са покрити със сиво-белезникав налеп, който се снема лесно, <p>а подлежащата тъкан е хипе</p><p>ремирана и оточна.</p></li><li><p><strong>Микроскопски</strong>: </p><p>Фибриновият налеп покрива </p><p>покривния епител, които на места е десквамиран и </p><p>оточен, с възпалителен инфилтрат, сред който до</p><p>минират левкоцити.</p></li></ul><li><strong>Дълбока (псевдомембранозна):</strong> </li><ul><li><strong>Етиология</strong>: Развива се при <strong>дифтерия</strong> или отровни газове. </li><li><strong>Макроскопски</strong>: <p>Тонзилите са увеличени. </p>Налепът е мръсносив <p>или жълтобелезникав</p>, отделя се трудно и оставя разязвена, мръсночервена повърхност. </li><li><strong>Микроскопски</strong>: Фибринът прониква дълбоко в некротизираната лигавица, в която има хеморагии.</li></ul></ol><h3>Гнойна ангина</h3><ul><li><strong>Лакунарна:</strong> В криптите на тонзилите се натрупва фибрин, левкоцити и епителен детрит.</li><li><strong>Флегмонозна:</strong> Обикновено едностранна. Тонзилите са силно увеличени и флуктуират; при срез изтича обилна гной. Тъканта е пропита с левкоцити.</li><li><strong>Ангина на Ludowic (Людовик):</strong> Тежка форма на флегмонозна ангина, при която гнойта пропива пода на устната кухина (<strong>diaphragma oris</strong>) и може да се спусне към медиастинума.</li></ul><h3>Улцеро-некротична ангина</h3><ul><li><strong>Ангина на Plaut-Vincent:</strong> Засяга най-често едната сливица.<p> По налепите прилича на </p><p>псевдомембранозната ангина, но тук те се </p><p>отделят по-лесно и под тях се вижда язве</p><p>но-некротична повърхност, отделяща неп</p><p>риятна миризма.</p></li><li><strong>Ангина при агранулоцитоза:</strong> Свързана с агранулоцитоза и остра левкоза. Характерни са дълбоки некрози, като специфичното е <strong>липсата на левкоцити</strong> във възпалителния инфилтрат около тях.</li></ul><h3>Усложнения на острата ангина</h3><ol><li>Флегмонозната ангина може да се усложни с перитонзиларен абсцес, ретрофарингеален абсцес или медиастинит, при което може да се развие тромбоза на v. jugularis, сепсис или септикопиемия.</li><li><strong>Системни:</strong> <strong><u>Ревматизъм </u></strong>и <strong><u>остър гломерулонефрит </u></strong>(изключително чести).</li></ol><h2>Хронична ангина (Хроничен тонзилит)</h2><p>Процесът е трайно концентриран в тонзилите. Различават се две форми:</p><p><strong>1. Атрофичен тонзилит</strong> (предимно при възрастни)</p><ul><li><strong>Макро:</strong> Тонзилите са малки, плътни, с къпиноподобна повърхност и фиброзни повлекла.</li><li><strong>Микро:</strong> <p>Лимфните фоликули са намалени </p><p>по обем, като тъканта е прошарена от ивици съеди</p><p>нителна тъкан</p>. Налице са плазмоцити, фибробласти и фиброцити.</li></ul><p><strong>2. Хиперпластичен тонзилит</strong> (предимно при деца и млади хора)</p><ul><li><strong>Макро:</strong> Сливиците са силно увеличени. От лакуните се отделят жълто-белезникави <strong>тапички</strong> (слуз, фибрин и епител).</li><li><strong>Микро:</strong> Значителен брой и размер на лимфните фоликули, с доминиране на плазматични клетки в ексудата.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 40. Доброкачествени и злокачествени тумори на устната кухина.</h1><h2><strong style=\"color: rgb(88, 129, 87)\">Доброкачествени тумори</strong></h2><h3><strong>1. Мезенхимни – Лимфангиом</strong></h3><ul><li><strong>Макро:</strong> Недобре отграничени лезии.</li><li><strong>Микро:</strong> Състои се от разраснали ендотелни клетки, образуващи структури, подобни на лимфни съдове (кистични пространства).</li><li><strong>Характеристика:</strong> Пространствата съдържат еозинофилна материя (плазма). За разлика от хемангиома, тук <strong>няма еритроцити</strong>.</li></ul><h3><strong>2. Епителни – Папилом</strong></h3><ul><li><strong>Произход:</strong> Покривен епител. Предизвиква се от <strong>HPV</strong> (доказва се с имунохистохимия).</li><li><strong>Микро:</strong> Дървовидно разклонена строма, тапицирана отвън с плосък епител.</li></ul><h3><strong>3. Миобластен миом на Абрикосов (Грануларноклетъчен тумор)</strong></h3><ul><li><strong>Локализация:</strong> Най-често в езика (под формата на възелче).</li><li><strong>Микро:</strong> Клетки с полигонална форма и зърниста (грануларна), еозинофилна цитоплазма.</li><li><strong>Специфични белези:</strong></li><ul><li>Показват сходство с нервната тъкан (<strong>Шванови обвивки</strong>) и се позитивират за <strong>S100 proteine</strong>.</li><li><strong>Псевдоепителиоматозна хиперплазия:</strong> Покривният епител разраства силно и повлеклата му навлизат дълбоко сред туморните клетки.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Злокачествени тумори</strong></h2><h3><strong>1. Карцином на устната кухина</strong></h3><p>Най-често от епителен произход (карциноми). По-чест при мъже.</p><ul><li><strong>Макроскопски форми:</strong></li><ol><li><strong>Възловидна:</strong> Окръглено плътно образувание (размер на грахово зърно/череша), което инфилтрира и разрушава околната тъкан.</li><li><strong>Язвена:</strong> Язва с неправилна форма и плътни, синкаво-белезникави ръбове.</li></ol><li><strong>Микро:</strong> Плоскоклетъчен вроговяващ или невроговяващ карцином.</li><li><strong>Степени на диференциация (Сквамозен карцином):</strong></li><ul><li><strong>G1 (Високо):</strong> Обилно рогово вещество в центъра на гнездата — <strong>\"ракови перли\"</strong>.</li><li><strong>G2 (Умерено):</strong> Сквамозни клетки с по-малко ракови перли, които не са навсякъде.</li><li><strong>G3 (Ниско):</strong> Клетките едва личат като сквамозни, рядко се срещат ракови перли.</li><li><strong>G4:</strong> Познава се само с имунохистохимия.</li></ul></ul><h3><strong>2. Лимфоепителен карцином</strong></h3><p>Нискодиференциран карцином с обилна стромна реакция. Туморните клетки са покрити/скрити и се доказват с имунохистохимия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>III. Тумори на фаринкса</strong></h2><h3><strong>1. Карцином на фаринкса</strong></h3><ul><li><strong>Локализация:</strong> Лигавица на носоглътката, меко небце, задна и странична страна на фаринкса, тонзили и основа на езика.</li><li><strong>Варианти:</strong></li><ul><li><strong>Екзофитен:</strong> Полипозен.</li><li><strong>Ендофитен:</strong> Инфилтриращ; разрушава околните тъкани, синуси, орбита и основа на черепа.</li></ul><li><strong>Усложнения:</strong> Гноен синуит, менингит, офталмит.</li><li><strong>Микро:</strong> Плоскоклетъчен вроговяващ или невроговяващ карцином. Метастазира в регионални и медиастинални лимфни възли.</li></ul><h3><strong>2. Лимфоепителиом на фаринкса</strong></h3><ul><li><strong>Локализация:</strong> Лимфна тъкан на тонзилите, епи- и хипофаринкса, основа на езика.</li><li><strong>Макро:</strong> Мека консистенция без ясни очертания.</li><li><strong>Микро:</strong> Недиференциран плоскоклетъчен карцином с <strong>обилна лимфоцитна стромна реакция</strong>.</li><li><strong>Особености:</strong> Чувствителен на лъчетерапия. Метастазира по лимфогенен и хематогенен път.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center; color: rgb(88, 129, 87) !important\">Тема 41. Заболявания на зъбите. Гингивит. Кариес. Периодонтоза. Пулпит. Периапикална киста. Фиброзна дисплазия.</h1><h2><strong style=\"color: rgb(88, 129, 87)\">Гингивит</strong></h2><p>Възпаление на венците, което е тясно свързано с хигиенните навици.</p><ul><li><strong>Етиология:</strong> Основна причина е лошата хигиена, водеща до образуване на <strong>дентална плака</strong> – лепкави, безцветни налепи от бактерии, слюнчени протеини и десквамирани епителни клетки.</li><li><strong>Патогенеза:</strong> С времето плаката се минерализира и се превръща в <strong>зъбен камък</strong>. Бактериите в плаката разрушават емайла и образуват ерозии, които са предвестник на кариеса.</li><li><strong>Клинични особености:</strong> Когато плаката се натрупва около венечния ръб, се развива гингивит. При юноши заболяването често протича тежко, хронифицира и се характеризира с лесно кървене на венците.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Кариес</strong></h2><p>Дистрофично заболяване на емайла, дентина и цимента, водещо до дефект в архитектониката на зъба.</p><ul><li><strong>Етиология и морфогенеза:</strong> Хранене с въглехидрати, които активират бактерии. Те произвеждат <strong>млечна киселина</strong>, разрушаваща органичното вещество и разтваряща калциевите соли на зъбите.</li><ul><li><p>Смята се че флуоридизацията на водата води до натрупване на флуориди в кристалните </p><p>структури на емайла, образува се т.н <strong>флуороапатити </strong>и се повишава резистентността за </p><p>разграждане от бактериалните киселини.</p></li></ul><li><strong>Видове по дълбочина:</strong></li><ol><li><strong>Повърхностен кариес:</strong> Разрушава се само <strong>емайлът</strong>. <br>Макроскопски се вижда мътнобелезникаво или кафяво петно. <br>Микроскопски: намаляване на калциевти соли, деформация и разпад на емайловите призми.</li><li><strong>Средно дълбок кариес:</strong> Процесът навлиза в <strong>дентина</strong>. <br>Микроскопски: деструктивни изменения в дентиновите каналчета като се виждат микробни колонии в тях. Около кариозното огнище се натрупват калциеви соли с образуване на&nbsp;<strong>вторичен (заместителен) дентин</strong> с неправилна структура като защитна реакция.</li><li><strong>Дълбок кариес:</strong> Дефектът стига до или прониква в <strong>пулпата</strong>, предизвиквайки пулпит.</li></ol><li><strong>Усложнения</strong>: <p>Пулпит и периодонтит, които могат да доведат до периапикален абсцес, остеомиелит или септикопиемия. При хронифициране се развиват хроничен пулпит и периапикален гранулом.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Пулпит</strong></h2><p>Остро или хронично възпаление на зъбната пулпа.</p><ul><li><strong>Етиология:&nbsp;</strong><p>Механична травма, химични увреждания и бактериални инфекции.</p></li><li><p><strong>Морфогенеза</strong>: Най-често при кариес или апикално увреждане с достъп до пулпата, по-рядко при интактна зъбна обвивка. Бива остър и хроничен пулпит.</p><br></li><li><strong>Остър пулпит: </strong>според ексудата бива серозен, гноен и некротичен.</li><ul><li><strong>Серозен:</strong>&nbsp;</li><ul><li>Макро: хиперемирана и оточна пулпа.</li><li>Микро: единични левкоцити, стаза и оток.</li></ul><li><strong>Гноен:</strong></li><ul><li><p>Макро: пулпа, пропита с гной, възможно изтичане през кариесен отвор.</p></li><li><p>Микро: гноен ексудат, деструкция, много левкоцити и некроза на одонтобласти.</p></li></ul><li><strong>Некротичен (Гангренозен):</strong>&nbsp;</li><ul><li><p>Макро: кафяво-черна пулпа с неприятна миризма; възможен гангренозен пулпит.</p></li><li><p>Микро: некротична тъкан и бактериални колонии.</p></li></ul></ul><li><strong>Хроничен пулпит:</strong>&nbsp;</li><ul><li><p>Микро: пролиферация на съединителна и гранулационна тъкан, хиалинизация и калциеви отлагания; инфилтрат от лимфоцити, плазмоцити, фибробласти и фиброцити. Възможни <strong>възпалителен полип </strong>и гигантски клетки.</p></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Перидонтит</strong></h2><p>Остро или хронично възпаление на периодонта (тъканите около корена).</p><ul><li><strong>Етиология</strong>: Най-често <p>стрептококови и стафилококови инфекции</p>.&nbsp;</li><li><strong>Морфогенеза</strong>: Инфекцията прониква от гингивити или кариеси към периодонта.</li><li><strong>Остър периодонтит:</strong>&nbsp;</li><ul><li><p>Микро: започва със серозно възпаление с хиперемия и оток, по-късно преминава в гноен периодонтит с гной около зъба и остеопластични/остеокластични промени. Възможно разпространение към меките тъкани.</p></li></ul><li><strong>Хроничен периодонтит:</strong>&nbsp;</li><ul><li><p>Микро: гранулационна тъкан с ксантомни клетки, холестеролови кристали и гигантски клетки → <strong>зъбен гранулом</strong>. Възможни фиброза при благоприятен изход или левкоцитна инфилтрация при обостряне и резорбция на алвеоларната кост.</p></li></ul><li><strong><p>Радикуларна (<u>периапикална</u>, зъбна) киста:</p>:</strong></li><ul><li><p>Възниква най-често след апикален абсцес и гранулом.</p></li><li><p>Макро: кистична формация с гранулационна тъкан и <strong>многослоен плосък епител</strong>, водеща до костна атрофия.</p></li><li><p>Усложнения: фистула и костна фрактура.</p></li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Парадонтоза</strong></h2><p>Хроничен възпалително-дегенеративен процес на целия зъбоподдържащ апарат.</p><ul><li><p><strong>Етиология</strong>: Нарушена нервна трофика, имунни механизми и смущения в микроциркулацията.</p><br></li><li><strong>Клиника:</strong> Започва с хроничен гингивит. Образуват се <strong>дълбоки джобове</strong> между зъба и периодонта, пълни с<p> хранителни остатъци, ексудат и бактерии, водещи до разклащане на зъбите. Развиват се и дистрофични промени в алвеоларните прегради, които могат да причинят падане на зъбите.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Обобщение на усложненията:</strong></h2><p>Кариес <span class=\"strut\" style=\"height: 0.3669em\"></span>→ Пулпит <span class=\"strut\" style=\"height: 0.3669em\"></span>→ Периодонтит <span class=\"strut\" style=\"height: 0.3669em\"></span>→ Периапикален абсцес / Гранулом / Киста <span class=\"strut\" style=\"height: 0.3669em\"></span>→ Остеомиелит или Септикопиемия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>Фиброзна дисплазия??</strong></h2><p>Доброкачествено тумороподобно заболяване, при което нормалната кост се замества от фиброзно-костна тъкан поради спряло развитие.</p><ul><li><strong>Клинични форми:</strong></li><ol><li><strong>Моноосална:</strong> Засяга само една кост. Среща се при деца и млади хора. По-честа е в <strong>максилата</strong> (горната челюст), отколкото в мандибулата.</li><li><strong>Полиосална:</strong> Засяга няколко кости едновременно.</li></ol><li><strong>Генезис:</strong> Дължи се на генетично нарушение. Клинично се проявява като плътна формация, която може да доведе до разместване и загуба на зъби.</li><li><strong>Хистологична картина:</strong></li><ul><li>Характерни <strong>костни гредички</strong> – те са деформирани, извити (често описвани като \"китайски йероглифи\").</li><li>Гредичките са разположени сред <strong>плътна фиброзна тъкан</strong>.</li><li><strong>Важен белег:</strong> Около костните гредички <strong>липсват остеобласти</strong> (липса на остеобластен \"кант\"), което я отличава от други костни процеси.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 42. Тумори на челюстите. Видове.</h1><p>Това са тумори, произхождащи от специализирани съставки на <strong>зъбната пластинка</strong>. Най-чести са <strong>амелобластомът</strong> и <strong>аденоамелобластомът</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Амелобластом</h2><p><strong>Синоним:</strong> адамантинома (<em>adamantinom</em>).\nТова е най-честият <strong>одонтогенен тумор</strong>.</p><h3>Честота</h3><p>Среща се най-често между <strong>20–50 години</strong>.</p><h3>Макроскопски</h3><p>Представлява <strong>сивобелезникав възел</strong> в <strong>мандибулата</strong>, който може да бъде:</p><ul><li>плътен</li><li>кистичен, изпълнен със светложълтеникава течност</li></ul><h3>Микроскопски</h3><p>Различават се няколко варианта:</p><ul><li><strong>Фоликуларен вариант</strong> – епителни повлекла, тапицирани с цилиндрични клетки, с многоъгълни и звездовидни клетки във вътрешността.</li><li><strong>Плексиформен вариант</strong> – анастомозиращи епителни повлекла от цилиндрични и кубични клетки, почти без строма. Понякога централно има кухина без клетки.</li></ul><p>И двата варианта са <strong>доброкачествени</strong>, но рядко могат да <strong>малигнизират</strong> и да <strong>метастазират</strong> в белите дробове.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 43. Възпалителни и туморни заболявания на слюнчените жлези. Морфологична характеристика.</h1><h2>Сиалоаденит</h2><p><strong>Сиалоаденитът</strong> е първично или вторично, остро или хронично възпаление на слюнчените жлези, срещано предимно в детска възраст.</p><h3>Етиология</h3><p>Най-често се причинява от:</p><ul><li><strong>вирусни инфекции</strong> – парамиксовирус, цитомегаловирус</li><li>по-рядко – <strong>бактериални инфекции</strong></li></ul><h3>1. Епидемичен паротит</h3><p>Типичен вирусен сиалоаденит.\nХарактеризира се със <strong>серозно възпаление</strong>. Слюнчените жлези са увеличени и уплътнени.</p><h4>Микроскопски</h4><p>Наблюдават се:</p><ul><li>оток на интерстициалната съединителна тъкан</li><li>фибриноидна дегенерация</li><li>възпалителен инфилтрат от лимфоцити, плазмоцити и хистиоцити</li><li>вакуолизация на ацинарния епител</li><li>паренхимна дегенерация на каналчестия епител</li></ul><h3>2. Цитомегален паротит</h3><h4>Микроскопски</h4><p>В епителните клетки на интралобуларните канали се откриват и вътрецитоплазмени включвания.</p><h3>3. Бактериален сиалоаденит</h3><p>По-рядък, свързан с инфекции в устната кухина.</p><h4>Микроскопски</h4><ul><li>при остри форми доминират <strong>левкоцити</strong></li><li>при хронични – <strong>лимфоцити и плазмоцити</strong> с изразен фибропластичен процес</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тумори на слюнчените жлези</h2><p>Преобладават тумори от <strong>епителен произход</strong>, които биват доброкачествени и злокачествени.</p><h2>Доброкачествени тумори</h2><h3>Плеоморфен аденом</h3><p><strong>Синоним:</strong> „смесен“ тумор.\nПроизхожда главно от големите слюнчени жлези и по-точно от дуктални епителни и миоепителни клетки.</p><p><strong>Макроскопски\n</strong>Добре капсулирано възловидно образувание до <strong>5 cm</strong>.</p><p><strong>Микроскопски\n</strong>Характеризира се с голямо хистологично разнообразие:</p><ul><li>цилиндрични и кубични клетки формират ацинозни и тубуларни структури</li><li>нарушен клетъчен поларитет</li><li>секреция на еозинофилна материя в стромата</li><li><span class=\"editor-note\" data-note=\"**Миксоматозна трансформация на стромата** – стромата придобива рехав, слузест (мукоиден) вид поради натрупване на мукополизахариди.\" id=\"note-1777735071220-0\">миксоматозна трансформация на стромата</span></li><li>звездовидни епителни клетки</li></ul><p>Възможна е плоскоклетъчна метаплазия с формиране на <strong>мукоепидермоиден вариант</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Злокачествени тумори</h2><p>Преобладават <strong>епителните малигнени тумори</strong>, отличаващи се с голямо хистологично разнообразие.\nПо-чести видове са:</p><ul><li><strong>мукоепидермоиден карцином</strong></li><li><strong>аденокарцином</strong></li><li><strong>аденоидно-кистичен карцином</strong></li><li><strong>онкоцитен карцином</strong></li><li><strong>миоепителен карцином</strong></li><li><strong>лимфоепителен карцином</strong></li></ul><p>Развиват се главно в:</p><ul><li>паротидната жлеза</li><li>малките слюнчени жлези на устната кухина, фаринкса, ларинкса, носа, синусите и трахеята</li></ul><p>Хистологичният вариант и степента на диференциация имат прогностично значение.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лимфоми на слюнчените жлези</h2><p>Слюнчените жлези са честа локализация на:</p><ul><li><strong>Хочкинови лимфоми</strong></li><li><strong>нехочкинови В-клетъчни лимфоми</strong></li></ul><p>Типични са <strong>екстранодалните маргинално-зонови В-клетъчни (MALT) лимфоми</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 44. Заболявания на хранопровода. Ахалазия. Синдром на Малори-Вайс. Варици.</h1><p><span style=\"color: rgb(88, 129, 87)\"><strong><span class=\"editor-note\" data-note=\"# Анатомия и физиология на хранопровода\n---\n## Обща характеристика\nХранопроводът е разположен в **задния медиастинум** и е с дължина **23–25 cm** – от фарингса до кардията на стомаха.\nПо хода му има три физиологични стеснения:\n* при крикоидния хрущял\n* при бифуркацията на трахеята\n* при диафрагмалния отвор (хиатус)\nТова са местата, където най-често настъпват увреждания и перфорации при травми и чужди тела.\n---\n## Долна трета на хранопровода\nДолната трета има важно функционално значение, тъй като действа като **сфинктерен механизъм**, предпазващ от рефлукс на стомашно съдържимо.\n---\n## Лигавица\nЛигавицата е със **сивкавобелезникав цвят** и е покрита с **многослоен плосък невроговяващ епител**, богат на гликоген.\nПод епитела се разполагат:\n* тънък слой **muscularis mucosae**\n* субмукоза със слузни езофагеални жлези\n* оскъдни лимфоцитни инфилтрати и малки лимфни фоликули\nОт субмукозата към епитела навлизат съединителнотъканни протрузии – **интраепителни папили**, достигащи до 1/3 от дебелината на епитела.\n---\n## Мускулен слой\nСъстои се от:\n* добре развит **циркулярен слой**\n* **лонгитудинален слой** мускулни влакна\nОтвън хранопроводът е обвит от фиброзна тъкан на медиастинума. Липсата на сероза улеснява разпространението на възпаления и затруднява хирургичните интервенции.\n---\n## Биопсичен материал\nЕндоскопските биопсии най-често съдържат само езофагеален епител, а по-рядко и малко количество субмукозна съединителна тъкан.\" id=\"note-1777735159163-1\">Анатомия</span></strong></span>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ахалазия</h2><p>При <strong>ахалазия</strong> вестибулумът остава затворен въпреки перисталтичната вълна, което затруднява преминаването на храната към стомаха. Перисталтиката става неправилна и неефективна.</p><h3>Макроскопски</h3><p>Хранопроводът е дилатиран, с изтънена стена и удължен, а понякога и неправилно завъртян около оста си — <strong>мегаезофаг</strong>. Вестибулумът и кардията са <strong>фиброзно задебелени</strong>.</p><h3>Микроскопски</h3><p>В лигавицата се наблюдават възпалителни промени, често с разязвяване и развитие на <strong>левкоплакия</strong>. Характерни са дегенеративни изменения с намаляване и загуба на <strong>ганглийни клетки </strong>в нервния плексус, по-изразени в проксималните сегменти и във вестибулума.</p><h3>Ендоскопска биопсия</h3><p>Обикновено не е достатъчна за поставяне на диагнозата. Тя се потвърждава чрез изследване на оперативен материал след хирургична корекция на кардиоспазма. Рецидиви след нея обикновено не се описват.</p><h3>Усложнения</h3><ul><li>аспирация на съдържимо в дихателните пътища → <strong>аспирационна пневмония </strong>или <strong>белодробен абсцес</strong></li><li>повишен риск от развитие на <strong>карцином на хранопровода</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Синдром на Малори-Вайс</h2><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Варици на хранопровода</h2><h3>Етиология</h3><p>Вариците представляват варикозно разширение на вените на езофагеалния венозен плексус вследствие на <strong>портална хипертония</strong>.\nПричините могат да бъдат:</p><ul><li><strong>прехепатални</strong> – портална или лиенална тромбоза</li><li><strong>интрахепатални</strong> – най-често чернодробна цироза, по-рядко карцином на черния дроб</li><li><strong>постхепатални</strong> – констриктивен перикардит, синдром на Budd-Chiari</li></ul><h3>Макроскопски</h3><p>Повишеното налягане води до разширяване на вените, най-силно в долната, по-слабо в средната трета на хранопровода. Те се нагъват по надлъжната ос и изпъкват под лигавицата.</p><p>Вариците могат да руптурират и да причинят масивен кръвоизлив с <strong>хематемеза</strong>, често с фатален изход. Понякога на мястото на руптурата се установява тромбоза.</p><p>При резекционен материал и аутопсия вариците трудно се доказват, тъй като след руптура или прерязване колабират.</p><h3>Микроскопски</h3><p>Субмукозните венозни съдове са асиметрично разширени с възловидни или фузиформени изпъквания.</p><p>Стената им варира от:</p><ul><li>задебелени участъци с фиброза и компенсаторна хипертрофия</li><li>до силно изтънени зони в най-разширените участъци</li></ul><p>Често се откриват тромби с различна давност. Лигавицата може да е непроменена или да показва възпаление, ерозии и повърхностни язви.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 45. Езофагити – видове. Баретов езофаг. Неоплазми на хранопровода.</h1><h2>Езофагит</h2><h3>Етиология</h3><p><strong>Езофагитът</strong> рядко е първично заболяване и най-често възниква вторично. Причини са:</p><ul><li>корозивни химични вещества</li><li>много горещи храни, течности и алкохол</li><li>ендогенни токсини при уремия</li><li>бактериални и гъбични инфекции</li><li>синдром на Plummer-Vinson</li><li>най-често — <strong>гастроезофагеален рефлукс</strong></li></ul><h3>Клиника</h3><p>Проявява се с:</p><ul><li><strong>дисфагия</strong></li><li>ретростернална болка</li><li>по-рядко хематемеза и мелена</li></ul><h3>Ендоскопско изследване</h3><p>Ендоскопията различава езофагита от <strong>езофагомалация</strong> — постмортална автолиза на лигавицата с „леопардови петна“, но без възпалителна реакция.</p><h3>Макроскопски</h3><p>Промените варират от хиперемия и оток до фибринозни налепи, некрози и язви.</p><ul><li>при корозивни вещества → масивна некроза и възможна перфорация</li><li>при уремия → псевдомембранозен езофагит</li><li>при рефлукс → ерозии и язви</li><li>при кандидоза → сиво-бели налепи с гъбични колонии</li></ul><p>При хронифициране могат да се развият <strong>Баретов езофаг</strong>, стенози и стриктури.</p><h3>Остър езофагит</h3><h4>Микроскопски</h4><p>Налице е възпалителен инфилтрат с доминиране на <strong>левкоцити</strong>, проникващ и в епитела. Съдовете са силно кръвонапълнени — картина на катарално възпаление.</p><p>Възпалението може да бъде фибринозно, флегмонозно, ерозивно-язвено или гангренозно.</p><p><strong>Корозивен езофагит\n</strong>Лигавицата е частично или напълно некротична с кръвоизливи и възможна перфорация.</p><p><strong>Кандидозен езофагит\n</strong>Наблюдават се ерозии и язви с <strong>ПАС-позитивни псевдомицели и псевдоспори</strong>. Инфилтратът е богат на левкоцити и еозинофили.</p><h4>Изход</h4><p>Острите форми могат да преминат без остатък, но при язвени и корозивни езофагити се развиват фиброза и склероза със <strong>стриктури на хранопровода</strong>.</p><h3>Хроничен езофагит</h3><h4>Микроскопски</h4><p>Лигавицата съдържа хроничен възпалителен инфилтрат от лимфоцити, плазмоцити, макрофаги и фибробласти.</p><p>Епителът показва:</p><ul><li>акантоза</li><li>паракератоза и хиперкератоза</li><li><strong>балонна дегенерация</strong></li><li>хиперплазия на папилите</li><li><strong>базалноклетъчна хиперплазия</strong></li></ul><p>При активност се появяват левкоцити, ерозии и язви.</p><h4>Изход</h4><p>Хроничният езофагит, особено при гастроезофагеален рефлукс, може да доведе до стенози и стриктури.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Баретов езофаг</h2><p>Баретовият езофаг представлява заместване на плоския епител в дисталния хранопровод с цилиндричен епител, подобен на стомашния. Свързва се най-често с <strong style=\"color: rgb(31, 41, 55)\">гастро-езофагеален рефлукс</strong>.</p><p>Днес се различават два типа Баретов езофаг.</p><ul><li><strong>Придобит (типичен) Баретов езофаг</strong></li><ul><li><strong>Етиология:\n</strong>Развива се вследствие на хроничен <strong>гастро-езофагеален рефлукс</strong>.</li><li><strong>Морфогенеза:\n</strong>При хроничен, често ерозивно-язвен езофагит настъпва непълна регенерация и последваща <strong>метаплазия</strong> на плоския езофагеален епител в цилиндричен муцинозен епител от стомашен тип.\nПромените се локализират в дисталния хранопровод, до 3 cm над кардията.</li></ul><li><strong>Вроден тип Баретов езофаг:\n</strong>Представлява вродена ектопия на стомашна лигавица в хранопровода. Среща се предимно при деца и по-често в горните отдели на хранопровода.</li></ul><h3>Честота и клиника</h3><p>Среща се най-често между <strong>50–70 години</strong>, без съществена разлика между половете.</p><p>Клиничната картина не е специфична и включва:</p><ul><li>парене и болка в епигастриума</li><li>дисфагия</li></ul><p>Често се съчетава с язвена болест, полипозен гастрит, стомашни тумори и хиатусна херния.</p><h3>Макроскопски</h3><p>Ендоскопски се виждат <strong>червени плаки </strong>или поленца с вид на стомашна лигавица, <strong>контрастиращи </strong>с нормалния <strong>сивкавобелезникав </strong>езофагеален епител.</p><p>Промените могат да имитират полипи и с напредване на процеса да доведат до стриктури.</p><h3>Микроскопски</h3><p>Плоският езофагеален епител е заместен от цилиндричен муцинозен епител, най-често подобен на кардиалния стомашен епител — <strong>кардиален тип Баретов езофаг</strong>.</p><p>По-рядко се среща:</p><ul><li><strong>фундусен тип</strong> – с главни и пристенни клетки</li><li><strong>интестинален (специализиран) тип</strong> – с интестинална метаплазия, формиране на въси и крипти</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Доброкачествени тумори</h2><h3>Мезенхимни тумори</h3><p>Те са редки и най-често са разположени интрамурално в субмукозата.</p><p><strong>Макроскопски\n</strong>Представляват малки, плътни, сивкави образувания до 3 cm. Най-чести са:</p><ul><li>лейомиоми</li><li>хемангиоми</li><li>неврофиброми</li><li>фиброваскуларни полипи</li><li>зърнистоклетъчни тумори</li></ul><p>Обикновено се откриват постмортем.</p><h3>Епителни тумори</h3><h4>Плоскоклетъчен папилом</h4><p>Може да бъде диагностициран чрез ендоскопска биопсия.</p><p><strong>Макроскопски\n</strong>Представлява малко полипозно-папиларно разрастване на лигавицата, най-често в дисталната част на хранопровода. Разположено е на тясна или широка основа и лесно кърви при допир по време на ендоскопията.</p><p><strong>Микроскопски\n</strong>Наблюдават се папиларни плоскоепителни разраствания върху богата на съдове фиброзна строма. Епителната подредба е запазена, но има базалноклетъчна хиперплазия и акантоза. Липсват паракератоза и хиперкератоза.</p><p><strong>Диференциална диагноза\n</strong>Папиломът трябва да се различава от:</p><ul><li>левкоплакия</li><li>възпалителни полипи при ерозивен и язвен езофагит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Злокачествени епителни тумори - Карцином на хранопровода</h2><h3><strong>Честота и рискови фактори\n</strong><br></h3><p>Ракът на хранопровода е сравнително рядък. По-често засяга мъже и обикновено се среща между 50–60 години.</p><p>Рискови групи са:</p><ul><li>пушачи</li><li>алкохолици</li><li>пациенти със синдром на Plummer-Vinson</li><li>ахалазия</li><li>Баретов езофаг</li></ul><h3><strong>Клиника\n</strong><br></h3><p>Ранните форми протичат безсимптомно. При поява на дисфагия туморът обикновено е напреднал. Само малък процент от пациентите имат 5-годишна преживяемост.</p><h3><strong>Макроскопски\n</strong><br></h3><p>Най-често туморът е локализиран в долната трета на хранопровода. Ранните лезии изглеждат като малки сиво-бели плаки. Туморът расте по надлъжната ос и постепенно обхваща стената или изпъква в лумена.</p><p>Различават се три макроскопски форми.</p><p><strong>1. Язвена форма\n</strong>Най-честа форма. Централно настъпва некроза с относително запазени периферни части. В някои случаи тези периферни ръбове силно изпъкват и се формира т.нар. рак с форма на \"паница\".\n</p><p>Некрозата може да обхване в дълбочина цялата стена и туморът да инфилтрира в околните тъкани и органи с развитие на:</p><ul><li>медиастинит</li><li>плеврит</li><li>перикардит</li><li>езофаго-бронхиална фистула</li><li>аспирационна пневмония и белодробна гангрена</li></ul><p><strong>2. Полипозно-папиларна форма\n</strong>По-рядка форма с разрастване към лумена под формата на белезникави маси тип „цветно зеле“. При разпад може да премине в язвена форма.</p><p><strong>3. Скирозна форма\n</strong>Представлява циркулярно белезникаво уплътнение на стената. Хранопроводът става ригиден и се развива изразена стеноза. Разязвяването е рядко и повърхностно.</p><h3>Микроскопски</h3><p>В 80–90% от случаите карциномът е <strong>плоскоклетъчен</strong>, с различна степен на диференциация и вроговяване.\nДруг важен хистологичен тип е <strong>аденокарциномът</strong>, който често възниква на базата на <strong>Баретов езофаг</strong>.\nИнфилтративният растеж може да бъде ограничен до субмукозата и мускулния слой или да обхване цялата стена и околните тъкани.</p><h3>Метастазиране</h3><p>Метастазира главно в регионалните лимфни възли и вътрешните органи.</p><ul><li>Туморите в долната трета метастазират към медиастинални лимфни възли и органи под диафрагмата.</li><li>Високо разположените тумори метастазират към шийни и надключични лимфни възли и могат да инфилтрират ларинкса, трахеята и щитовидната жлеза.</li></ul><p>Разпространение по лимфните съдове на стената води до надлъжни белезникави ивици под лигавицата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Злокачествени мезенхимни тумори</h2><p>Саркомите на хранопровода, като <strong>леиомиосарком</strong> и <strong>фибросарком</strong>, са изключително редки.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 46. Гастрит. Видове, морфологична характеристика.</h1><p><strong>Гастритът</strong> е един от най-честите патологични процеси в храносмилателния тракт. Протича в две основни форми: <strong>остър</strong> и <strong>хроничен гастрит</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър гастрит</h2><p><strong>Острият гастрит</strong> е полиетиологично заболяване, което често има транзиторен характер и може да завърши с пълно възстановяване. При чести рецидиви може да хронифицира.</p><h3>Етиология</h3><p>Причините се разделят на <strong>екзогенни</strong> и <strong>ендогенни фактори</strong>.</p><ul><li><strong>Екзогенни фактори</strong> са груба, лоша или трудно смилаема храна, много горещи или студени храни и напитки, <strong>алкохол</strong>, <span class=\"editor-note\" data-note=\"салицилати, сулфонамиди, антибиотици, кортикостероиди, дигиталис\" id=\"note-1777739973056-0\">медикаменти</span>, корозивни химични вещества, токсини и бактерии (стрепто- и стафилококи, салмонела, коли бактерии и особено <strong>Helicobacter pylori</strong>).</li><li><strong>Ендогенни фактори</strong> са токсични продукти при уремия, имунни комплекси и <span class=\"editor-note\" data-note=\"коремен тиф, дифтерия, сепсис, вирусен хепатит, инфекциозна мононуклеоза, скарлатина и др\" id=\"note-1777739990437-1\">инфекции с вторично хематогенно засягане на стомашната лигавица</span>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Форми на остър гастрит</h2><h3>Остър катарален гастрит</h3><p><strong>Макроскопски:</strong> Лигавицата е оточна, хиперемирана, задебелена и с грубоват релеф. По повърхността може да има <strong>ерозии</strong> и точковидни кръвоизливи под слой слуз и излющен епител.</p><p><strong>Микроскопски:</strong> Наблюдават се дегенеративни и некробиотични промени в епитела, повърхностни ерозии, оток и силна съдова конгестия. Собственият слой на лигавицата е обилно инфилтриран с <strong>левкоцити</strong>, а на места има диапедезни кръвоизливи. В повърхностния и ямковия епител се откриват мигрирали левкоцити — <strong>левкодиапедеза</strong>. Слузната секреция е неравномерно потисната, а жлезите са без съществени промени, но със снижена секреторна активност. При множествени ерозии се говори за ерозивен гастрит.</p><h3>Остър фибринозен гастрит</h3><p><strong>Макроскопски</strong>: По повърхността на гънките има мръсносивкав или жълто-кафяв налеп. След отстраняването му се откриват ерозии или язви.</p><p><strong>Микроскопски:</strong> Налепът е от <strong>фибрин</strong>, левкоцити и излющени епителни клетки. Такъв характер има гастритът при <strong>уремия</strong> и <strong>дифтерия</strong>.</p><h3>Остър гноен / флегмонозен гастрит</h3><p>Тежка форма, най-често причинена от <strong>стрептококи</strong>. Инфекцията навлиза през увредена лигавица (хронична язва, разязвен карцином) или по <span class=\"editor-note\" data-note=\"при сепсис, еризипел, фурункулоза и др\" id=\"note-1777740166504-2\">хематогенен път</span>.</p><p><strong>Макроскопски:</strong> Може да бъде ограничен, абсцедиращ, или дифузен — <strong>флегмон на стомаха</strong>. Стената е задебелена, при срез изтича жълто-зелена гной или се виждат абсцеси. Лигавицата е с груб релеф, кръвоизливи и фибринен налеп.<br><strong>Микроскопски:</strong> Има обилна гнойна инфилтрация с левкоцити, предимно в субмукозата, но може да обхване цялата стена до серозата. В засегнатите зони могат да се образуват абсцеси. Наблюдават се съдова конгестия и тромби. При ангажиране на серозата може да се развиват перигастрит и гноен перитонит.</p><h3>Некротичен / корозивен гастрит</h3><p>Възниква при контакт с корозивни вещества — киселини, основи и др.</p><p><strong>Макроскопски:</strong> Развива се некроза на лигавицата, която може да бъде коагулационна или коликвационна, повърхностна или дълбока, до <strong>перфорация </strong>на стомашната стена. При преживяване настъпват тежки фиброзно-склеротични промени с деформация и стеноза на стомаха.</p><h3>Остър хеморагичен гастрит</h3><p>Причинява се от медикаменти, особено аспирин, травми, големи операции и някои инфекции (антракс, чума, хеморагична треска).</p><p><strong>Макроскопски:</strong> Лигавицата е осеяна с точковидни или конфлуиращи кръвоизливи и ерозии, придаващи ѝ пъстър или интензивно червен вид.</p><p><strong>Микроскопски:</strong> Наблюдават се силна съдова конгестия, повърхностни некрози, кръвоизливи и оток в лигавицата и субмукозата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен гастрит</h2><p><strong>Хроничният гастрит</strong> включва възпалителни, дегенеративни, вазомоторни и трофични нарушения с последваща <strong>атрофия </strong>и структурна преустройка на лигавицата.</p><h3>Етиология и морфогенеза</h3><p>Факторите се припокриват с тези при острия гастрит, но участват още <strong>автоимунни механизми</strong>, генетична предиспозиция, възрастови и хормонални фактори, нарушения в кръвоснабдяването и др.</p><p><strong>Имунни механизми:</strong> \n</p><ul><li>При <strong>тип А гастрит</strong> се откриват антитела срещу пристенните клетки и intrinsic factor. Свързва се с пернициозна анемия и други автоимунни заболявания.</li><li>При<strong> гастрит тип В</strong> автоимунните механизми са по-слабо изразени. Срещат се антитела срещу G-клетките в антрума и дефицит на гастрин.</li></ul><p><strong>Алкохол:</strong> \nПричинява нарушения в микроциркулацията, микрокръвоизливи, оток, микротромби и епителни некрози.</p><p><strong>НСПВП:</strong> \nАспирин, индометацин и други водят до ерозии, кръвоизливи и условия за хроничен гастрит.</p><p><strong>Дуодено-гастрален рефлукс:</strong> \nЖлъчните киселини и компонентите на дуоденалното съдържимо увреждат лигавичния епител и поддържат хронично възпаление.</p><p><strong>Helicobacter pylori:</strong> \nНарушава защитата на лигавицата, особено слузната секреция, и поддържа възпалителния процес.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация на хроничния гастрит</h2><h3>По морфология</h3><ul><li>Хроничен гастрит без атрофия.</li><li><p>Хроничен атрофичен гастрит.</p><br></li><li>Стомашна атрофия.</li><li><p>Хипертрофичен гастрит на Menetrier.</p><br></li></ul><h3>По локализация</h3><ul><li>Антрален.</li><li><p>Корпусен.</p><br></li><li>Пангастрит (антрум и корпус).</li></ul><h3>По етиология</h3><ul><li><p>Helicobacter pylori-асоцииран.</p></li><li><p>Бактериален, вирусен, микотичен.</p><br></li><li><p>Реактивен (при рефлукс, алкохол, медикаменти).</p><br></li><li><p>Специални форми (грануломатозен - туберкулоза, саркоидоза; при болест на Crohn; еозинофилен, алергичен).</p><br></li><li>Идиопатичен (с неизяснена етиология).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен гастрит без атрофия</h2><p><strong>Ендоскопски: \n</strong>Лигавицата може да е без особени промени или да изглежда дифузно зачервена, обилно покрита със слуз, но със <strong>запазен релеф.</strong><br></p><p><strong>Микроскопски:</strong> </p><p>Дебелината на лигавицата е нормална или леко увеличена поради оток и възпалителна инфилтрация. Епителът е цилиндричен, на места по-нисък и кубичен, с дегенеративни промени и белтъчна дегенерация. Ямките могат да бъдат по-плитки, по-дълбоки или извити, без съществени промени в жлезите.</p><p>В корпусните жлези могат да се наблюдават четири важни промени: </p><ul><li><strong>Мукоидизация </strong><p>– увеличаване на муцинозните клетки в шийките и тялото на корпусните жлези с частично заместване на главните и пристенните клетки.</p></li><li><strong>Псевдопилорна трансформация </strong>- <p>пълно заместване на специализираните клетки с муцинозни и структурна преустройка на корпусната лигавица от псевдопилорен тип.</p></li><li><strong>Интестинална метаплазия </strong><p>– заместване на стомашния епител с чашковидни клетки от чревен тип в повърхностния епител и/или в дълбочина на корпуса и антрума.</p></li><li><strong>Париетализация на корпусните жлези </strong><p>– увеличаване до 1,5 пъти на броя на пристенните клетки в корпусните жлези.</p></li></ul><p>Собственият слой е инфилтриран главно от лимфоцити и плазмоцити, по-рядко еозинофили, неутрофили, хистиоцити и мастоцити. Инфилтратът е локализиран предимно в горната трета на лигавицата, поради което формата се означава и като <strong>повърхностен гастрит</strong>.</p><p>Слузната секреция е увеличена или леко редуцирана. При активност на процеса се наблюдават <strong>левкодиапедеза</strong>, силна съдова конгестия и намалена до липсваща слузна секреция.</p><p>Най-често засяга корпусната лигавица, по-рядко антрума или целия стомах като пангастрит.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен атрофичен гастрит</h2><p>Най-често засяга <strong>антрума</strong>, по-рядко протича като атрофичен пангастрит и най-рядко изолирано в корпуса.</p><p><strong>Ендоскопски:</strong> \nЛигавицата е <strong>бледа</strong>, <strong>блестяща </strong>и <strong>изтънена</strong>, с изгладен релеф и прозиращи субмукозни съдове.<br></p><p><strong>Микроскопски:</strong> \nЯмките са разширени и деформирани, понякога плитки и почти изгладени, а в други случаи дълбоки с изпъкнали гънки — <strong>вилизация</strong>.</p><p>Дебелината на стомашната лигавица е намалена вследствие на атрофия:</p><ul><li>при умерено изразен атрофичен гастрит лигавицата е умерено изтънена;</li><li>при тежък атрофичен гастрит изтъняването е силно изразено както в корпуса, така и в антрума.</li></ul><p>Епителът е нисък, кубичен, с хиперхромни ядра и понякога многоредност. Жлезите намаляват по брой, губят нормалното си подреждане и се раздалечават поради разрастване на съединителна тъкан. Мускулният слой на лигавицата е задебелен.</p><p>Възпалителният инфилтрат обхваща цялата дебелина на лигавицата и е съставен главно от <strong>лимфоцити </strong>и <strong>плазмоцити</strong>. Често се откриват <strong>Ръселови телца и интраепителиални лимфоцити</strong>.</p><p>Слузната секреция е неравномерно редуцирана, а с прогресиране на атрофията слузните клетки намаляват и изчезват. Намаляват и неутралните муцини и сиаломуцините.</p><p><strong>Форми и структурни промени</strong></p><ul><li><strong>Фоликуларен гастрит</strong> – <p>рядка форма с обилна кръглоклетъчна инфилтрация и формиране на лимфни фоликули с герминативни центрове</p>.</li><li><strong>Дълбок кистичен гастрит</strong> – <p>жлезите в дълбоките отдели на лигавицата претърпяват кистична дилатация и са тапицирани с приплеснат епител без слузна секреция</p>.</li><li><strong>Псевдопилорна трансформация</strong>.</li><li><strong>Интестинална метаплазия (ентеролизация)</strong> – огнищна или дифузна, със заместване на стомашния епител с чашковидни клетки от чревен тип.</li></ul><h4>Дисплазия</h4><p>Развива се най-често на фона на хроничен атрофичен гастрит и е свързана с риск от карцином.</p><p><strong>Микроскопски се наблюдават:</strong></p><ul><li>клетъчен атипизъм</li><li>нарушена диференциация</li><li>дезорганизация на архитектониката</li></ul><p>Различават се:</p><ul><li><strong>лека дисплазия</strong> – може да регресира и не се приема за преканцероза</li><li><strong>тежка дисплазия</strong> – отъждествява се с <strong>carcinoma in situ </strong>и може да премине в ранен стомашен карцином</li></ul><p>На фона на атрофията могат да се образуват и хиперпластични полипи.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Стомашна атрофия</h2><p><strong style=\"color: rgb(31, 41, 55)\">Стомашната атрофия</strong> е рядък процес, различен от крайния стадий на хроничния атрофичен гастрит. </p><p>Среща се при пернициозна или желязодефицитна анемия и някои автоимунни заболявания, като се развива по типа на <strong>гастрит А</strong>, на основата на автоимунен процес в стомашната лигавица.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен хипертрофичен гастрит</h2><p><strong>Синоними:</strong> гастрит на <strong>Menetrier</strong>, хипертрофична гастропатия.</p><p>Това е рядка форма, по-честа при мъже между 30–60 години.</p><p><strong>Макроскопски:</strong> \nХарактеризира се с хиперплазия на повърхностния и ямковия муцинозен епител, хипертрофия на стомашните гънки, хипохлорхидрия и белтък-губеща гастропатия. Лигавичните гънки са силно уголемени, груби и наподобяват мозъчна кора. Мукозата е червена или червено-кафеникава и покрита с дебел слой слуз. Промените са най-изразени по голямата кривина и обикновено липсват в антрума.</p><p><strong>Микроскопски:</strong> \n</p><p>Наблюдава се хиперплазия на муцинозните клетки в повърхностния и ямковия слой на лигавицата, както и частично в жлезите, някои от които са кистично разширени. Лигавицата е значително задебелена. В собствения слой има необилна възпалителна инфилтрация с преобладаване на плазмоцити и еозинофили.</p><p>На базата на хипертрофичната гастропатия по-често може да се развие <strong>карцином на стомаха</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 47. Пептична язвена болест. Усложнения.</h1><h2>Остра язва</h2><p>Острата язва представлява дефект в лигавицата на стомаха или дуоденума, който достига и разрушава мускулния слой на лигавицата. Често възниква вторично при други заболявания и се означава като симптоматична язва.</p><h3>Етиология</h3><p>Често остава идиопатична, най-честите причини за развитие са:</p><ul><li>травми, изгаряния и хирургични интервенции (Curling-ови язви);</li><li>инфекции – туберкулоза, сифилис;</li><li><p>мозъчносъдови нарушения, травма на мозъка </p><p>или интракраниални операции</p>;</li><li>ендокринни нарушения – тиреотоксикоза, паратиреоза, синдром на Zollinger-Ellison;</li><li>токсични фактори – уремия, алкохол, професионални вредности;</li><li>медикаменти – кортикостероиди, салицилати;</li><li>хипоксия и дисциркулаторни нарушения, напр. при остра или хронична СН;</li><li>тежки агонални състояния.</li></ul><h3>Морфогенеза</h3><p>Развива се при повишена солнокисела секреция и намалена лигавична протекция – нарушена слузна секреция, регенерация и кръвоснабдяване. Честа клинична проява на острата язва са кръвоизливите в стомашно-чревния тракт - от малки, скрити (окултни) кръвоизливи до хематемеза и мелена.</p><h3>Макроскопски</h3><p>Острите язви са обикновено множествени, кръгли, до 1 cm, с кафяво-черно дъно поради образуваният кисел хематин. Трудно разграничими от ерозии. Ръбовете са меки, неясно ограничени и често хиперемирани.</p><h3>Микроскопски</h3><p>Налице е остро възпаление в ръбовете и дъното на язвата, с левкоцитна инфилтрация, еритроцити и фибрин.</p><h3>Изход</h3><p>Може да настъпи пълна епителизация и оздравяване.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хронична язва</h2><p>Хроничната язва е хронично заболяване с цикличен ход, проявяващо се с рецидивиращи язви на стомаха или дуоденума. </p><p>Среща се често, предимно при градското население и по-често при мъже. Дуоденалните язви са по-чести от стомашните. Стомашната язва се среща по-често при мъже между 40–50 г. и жени над 50 г., а дуоденалната — главно при млади мъже между 30–40 г.</p><h3>Етиология и морфогенеза</h3><p>Важно значение имат <strong>неврогенните фактори</strong>, стресът и психоемоционалното напрежение. Те нарушават регулацията на стомашната секреция и моторика, активират n. vagus и водят до повишена солнокисела секреция.</p><p>При стомашната язва основно значение има <strong>понижената лигавична протекция </strong>— намалена слузна секреция, хроничен гастрит, хиповитаминози, белтъчен недоимък и намалена регенераторна способност.</p><p>При дуоденалната язва доминират <strong>агресивните фактори </strong>— хиперсекреция на солна киселина, ацидификация на дуоденума, висока вагусова активност, повишен гастрин и увеличена маса на пристенните клетки.</p><h3>Локализация</h3><p><strong>Стомашната</strong> язва най-често се локализира по малката кривина, в антрума, тялото на стомаха и пилора.</p><p><strong>Дуоденалната язва</strong> се разполага главно в проксималната част на дуоденума — по предната или задната стена на булбуса. Понякога се срещат симетрични „<strong>целуващи се язви</strong>“.</p><h3>Макроскопски</h3><p>Хроничната язва обикновено е <strong>единична</strong>, кръгла или овална, до 3 cm. Дефектът прониква в дълбочина през лигавицата и може да достигне серозата.</p><p>Дъното е гладко или зърнисто, понякога покрито с тъмни хематинни материи. При отмиването им може да се види ародиран или тромбозиран съд.</p><p>Ръбовете са надигнати, плътни, понякога мазолести — калозна язва. Ръбът към хранопровода е подкопан, а този към пилора е стъпаловидно наклонен. При напречен срез язвата има фуниевиден вид, а лигавичните гънки конвергират към дефекта.</p><p>Серозата в областта на язвата е задебелена и понякога срастнала със съседни органи.</p><h3>Микроскопски</h3><p><strong>Хронична активна (изострена) язва\n</strong>Характеризира се с:</p><ul><li>Дъно, покрито с <strong>детрит </strong>и <strong>фибринозно-гноен ексудат</strong>.</li><li>Широк слой <strong>фибриноидна некроза</strong>, обхващащ и съдовите стени.</li><li>Слой млада <strong>гранулационна тъкан</strong>, богата на тънкостенни съдове и клетки.</li><li>Слой зряла <strong>цикатрициална съединителна тъкан</strong>; съдовете са задебелени, с ендартериитни и ендофлебитни промени, често с тромби.</li></ul><p><strong>Хронична неактивна язва (ремисия)\n</strong>Характеризира се с:</p><ul><li>Липсва или е слабо изразен слоят на фибриноидна некроза.</li><li>Язвеното дъно се прораства от гранулационна тъкан.</li><li>Наблюдава се епителизация от нисък едно- или двуреден регенераторен епител.</li><li>Гранулационната тъкан съзрява и преминава в груба цикатрициална съединителна тъкан.</li><li>Съдовете са с фиброзно-склеротични промени, задебелени стени, стеснен лумен и организирани тромби.</li><li>В нервните окончания има разрастване на нервни влакна и Шванови клетки с формиране на „ампутационни невроми“.</li><li>Около стомашната язва обикновено има хроничен, често атрофичен и активен Helicobacter pylori-асоцииран гастрит, с възможни метапластични и диспластични промени.</li><li>Около дуоденалната язва може да има хроничен дуоденит, стомашна метаплазия и хипертрофия на Брунеровите жлези.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изход</h2><p>Изходът на хроничната язва е различен при отделните пациенти. Обилната цикатрициална тъкан и фиброзно-склеротичните съдови промени затрудняват заздравяването на дефекта.</p><p>При оздравяване:</p><ul><li>язвеният дефект се изпълва с гранулационна тъкан;</li><li>тя съзрява в зряла съединителна тъкан и формира цикатрикс с линеарен или звездовиден вид;</li><li>от съседната лигавица разраства регенераторен епител, който покрива цикатрикса с тънък еднореден слой клетки.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения</h2><p><strong>1. Кръвоизливи\n</strong>Най-честото усложнение (1/4–1/3 от пациентите). Могат да бъдат:</p><ul><li>окултни — при разрушаване на малки съдове;</li><li>масивни — при арозия на по-голям съд, с хематемеза и мелена, понякога фатални.</li></ul><p>  При тромбозиране на съда кръвоизливът може да спре.</p><p><strong>2. Перфорация\n</strong>Възниква при дълбок язвен дефект, достигащ серозата, обикновено при изостряне. Води до локален или дифузен перитонит. Понякога е първа клинична проява на язвата.</p><p><strong>3. Пенетрация\n</strong>Язвата прогресира през цялата стена и прониква в съседни органи — най-често панкреас, черен дроб, оментум, напречно дебело черво, по-рядко жлъчен мехур. Може да причини некроза, възпаление и фистули.</p><p><strong>4. Стеноза</strong>\nФиброзно-склеротичните промени причиняват:</p><ul><li>пилорна стеноза;</li><li>стеноза на кардията;</li><li>деформация на стомаха тип „пясъчен часовник“.</li></ul><p><strong>5. Възпалителни усложнения\n</strong>При ангажиране на серозата се развиват перигастрит или перидуоденит със сраствания към околните тъкани и органи.</p><p><strong>6. Малигнизация\n</strong>Най-тежкото усложнение; среща се при 1–2.6% от стомашните язви. Дуоденалните язви малигнизират изключително рядко.</p><p>Злокачественото израждане започва от язвените ръбове, на базата на усилени регенераторни процеси, поради което при ендоскопия задължително се биопсират язвените ръбове.</p><ul><li>Макроскопски: дъното е покрито с некротични материи и кръвоизливи; ръбовете са разръфани, подкопани и мековати.</li><li>Микроскопски: най-често аденокарцином, по-рядко мукоцелуларен карцином.</li><li>Диагнозата изисква доказване на остатъчни белези от хронична язва и разграничаване от регенераторни промени,&nbsp;<p>при които клетките са големи, със светла цитоплазма и много митози, но без хиперхромия и белези на атипия.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Прогноза</h2><p><strong>1. Оздравяване\n</strong>При адекватно лечение много язви заздравяват. При около 15% лечението е неефективно. Ваготомията и пилоропластиката са алтернативни методи.</p><p><strong>2. Рецидиви\n</strong>Най-чест ход на заболяването:</p><ul><li>около 50% рецидиви при 3-годишна анамнеза;</li><li>около 75% при 5-годишна анамнеза.</li></ul><p><strong>3. Кръвоизливи\n</strong>Около 5% изискват болнично лечение. Смъртността е:</p><ul><li>~20% при стомашни язви;</li><li>~30% при дуоденални язви.</li></ul><p><strong>4. Перфорация\n</strong>Среща се по-често при мъже. Прогнозата зависи от възрастта и времето до операцията. Смъртността е под 5%.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 48. Доброкачествени и злокачествени тумори на стомаха. Преканцерози.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 49. Нарушения в развитието на тънко и дебело черво. Мекелов дивертикул. Болест на Хиршпрунг.</h1><p><strong><span style=\"color: rgb(88, 129, 87)\"><span class=\"editor-note\" data-note=\"## Анатомия и физиология на тънкото черво\n**Тънкото черво** е с дължина **300–900 cm** и се разделя на:\n* **дуоденум** (~20 cm),\n* **йеюнум** (40%),\n* **илеум** (60%).\nИлеумът завършва с **илеоцекална клапа** със сфинктерна функция. Кръвоснабдяването се осъществява от **гастродуоденалната** и **горната мезентериална артерия**, а венозният дренаж е към **v. portae**.\nОсновната функция е **смилане и резорбция** на хранителни вещества. Смилането зависи от:\n* **pH**,\n* **жлъчна секреция**,\n* **панкреатичен сок**.\nРезорбцията се извършва чрез **проста дифузия** и **активен транспорт**. Важна роля имат ензимите на **„четковидната граница“**:\n* дизахаридази,\n* пептидази,\n* алкална фосфатаза,\n* ATP-аза,\n* хидролази.\nНай-активна абсорбция има в **проксималния йеюнум**.\n---\n## Нормална хистология\nСтената на тънкото черво включва:\n**лигавица**, **muscularis mucosae**, **субмукоза**, **мускулен слой** и **сероза**.\n**Лигавицата** е дебела **700–900 μm** и има кадифен вид поради наличието на **въси** и **крипти на Lieberkühn**.\n* **Въсите** са палцевидни израстъци към лумена.\n* **Криптите** са вдлъбвания между въсите.\nВисочината на въсите е **320–570 μm**, дълбочината на криптите — **100–120 μm**, а съотношението **въси : крипти** е **3–5 : 1**.\n### Епителни клетки\n* **Ентероцити** — високи цилиндрични клетки с микровили (**„четковидна граница“**), осъществяващи абсорбцията.\n* **Чашковидни клетки** — продуцират **слуз**, съдържаща **муцини и ГАГ**.\n* **Клетки на Панет** — разположени в дъното на криптите; съдържат **ацидофилни гранули** и имат **антимикробна функция**.\n* **Недиференцирани клетки** — стволови клетки с **висока митотична активност**.\n* **Ендокринни клетки** — секретират хормони, регулиращи моториката и секрецията.\n**Lamina propria** е изградена от рехава съединителна тъкан с:\n* колагенни и аргирофилни влакна,\n* лимфоцити,\n* плазмоцити,\n* еозинофили,\n* мастоцити.\nСрещат се и **интраепителни лимфоцити**.\n**Muscularis mucosae** се състои от циркулярни и надлъжни гладкомускулни влакна и разделя лигавицата от субмукозата.\n**Субмукозата** съдържа съдове, нервния плексус на **Meissner**, а:\n* в **дуоденума** — **Брунерови жлези**;\n* в **йеюнума и илеума** — **Пайерови плаки** и лимфни фоликули.\n**Мускулният слой** има вътрешен циркулярен и външен надлъжен слой, между които се разполага **плексусът на Auerbach**.\n**Серозата** представлява висцерален перитонеум, покриващ чревните бримки.\" id=\"note-1777748129316-3\">Анатомия</span>.</span></strong></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Аномалии в анатомията на тънкото черво</h2><h3>Дивертикули на дуоденума и тънкото черво</h3><p>Това е рядка патология, която обикновено протича без клинична симптоматика и често се открива случайно при рентгеново изследване или аутопсия.</p><p><strong>Локализация:\n</strong>Най-често дивертикулите се намират в:</p><ul><li><strong>постбулбарната част на дуоденума</strong>;</li><li>други отдели на тънкото черво.</li></ul><p>Могат да бъдат и множествени.</p><p><strong>Макроскопски:</strong></p><ul><li>В <strong>дуоденума</strong> дивертикулите са обикновено <strong>истински дивертикули</strong>, т.е. стената им съдържа <strong>всички слоеве на чревната стена</strong>.</li><li>В <strong>тънкото черво</strong> най-често са <strong>псевдодивертикули</strong>, при които стената съдържа само <strong>лигавица и субмукоза</strong>.</li></ul><p>При задържане на чревно съдържимо могат вторично да се развият:</p><ul><li>възпаление (<strong>дивертикулит</strong>);</li><li>обструктивни нарушения.</li></ul><h3>Мекелов дивертикул (дивертикул на Meckel)</h3><p>Представлява вродена аномалия, развиваща се от остатъци на <strong>ductus omphalomesentericus</strong>.</p><p><strong>Локализация:\n</strong>Разположен е в <strong>илеума</strong>, на около <strong>60–90 cm от илеоцекалната клапа</strong>.</p><p><strong>Макроскопски:\n</strong>Може да има вид на:</p><ul><li>тънка фиброзна връв;</li><li>дивертикул с широк лумен.</li></ul><p><strong>Микроскопски:\n</strong>Стената му е изградена от <strong>всички слоеве на чревната стена</strong>, поради което представлява <strong>истински дивертикул</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Болест на Хиршпрунг.</h2><br><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 50. Ентероколити. Класификация, морфологична характеристика.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 51. Синдром на лошо чревно всмукване. Видове. Болест на Уипъл.</h1><h2>Синдром на лошото всмукване (Malabsorption syndrome)</h2><h3>Етиология</h3><p>Свързва се с нарушения в <strong>абсорбцията и транспорта</strong> на хранителните вещества през тънкочревната стена. Най-важни са нарушенията във всмукването на <strong>мазнини, белтъци, витамини, минерали и соли</strong>.</p><h3>Клиника</h3><p>Проявява се с <strong>диария, стеаторея, загуба на тегло, анемия, остеопороза/остеомалация, хипокалиемия и хипокалциемия</strong>. Морфологично промените най-често имат вид на <strong>хроничен йеюнит (ентерит)</strong>.</p><h3>Заболявания с първична малабсорбция</h3><h4>Глутенова ентеропатия (цьолиакия)</h4><p>Известна е още като <strong>нетропическо/цьолиакично спру</strong>. При възрастни се означава като <strong>глутенова ентеропатия</strong>, а при деца – <strong>цьолиакия</strong>.</p><p><strong>Етиология\n</strong>Дължи се на непоносимост към <strong>глутен</strong>, по-специално към неговата фракция <strong>глиадин</strong>.</p><p><strong>Клиника\n</strong>Проявява се с <strong>диария, стеаторея, загуба на тегло и нарушено храносмилане</strong>. Установяват се повишени <strong>серумни IgA</strong> и отлагането им по базалната мембрана на епитела на въсите и криптите.</p><p><strong>Микроскопски\n</strong>Наблюдава се <strong>хроничен йеюнит</strong> с парциална (по-често) или субтотална атрофия на въсите. В инфилтрата преобладават <strong>лимфоцити</strong> и особено <strong>плазмоцити</strong>. Увеличени са <strong>чашковидните клетки</strong> и <strong>клетките на Paneth</strong>; редукцията на последните говори за лоша регенерация.</p><p>При субтотална атрофия чашковидните клетки намаляват, разрушена е <strong>„четковидната граница“</strong>, както и базалната мембрана. Намалена е активността на <strong>алкалната фосфатаза, АТФ-азата и аминопептидазата</strong>. При тежка атрофия ензимната активност във въсите може напълно да липсва.</p><p>Активността на <strong>сукциндехидрогеназата</strong> също е намалена, но се възстановява след изключване на глутена.</p><p>Промените при децата са идентични с тези при възрастните. След безглутенова диета възстановяването е по-добро при деца. При тежка атрофия пълно възстановяване често не се постига. <strong>Кортикостероидната терапия</strong> подпомага регенерацията.</p><h3>Заболявания с вторична малабсорбция</h3><h4>Дизахаридазна интолерантност</h4><p>Развива се след структурно увреждане на лигавицата с намалена активност на <strong>лактаза</strong> и <strong>сукраза</strong>. Морфологично се наблюдава различна степен на <strong>хроничен йеюнит</strong> и потисната дизахаридазна активност.</p><h4>Малабсорбция при механични и анатомични нарушения</h4><p>Среща се при дивертикули, стенози, фистули и постоперативни стриктури. Лигавицата може да е нормална или с промени тип хроничен йеюнит с парциална атрофия.</p><h4>Малабсорбция при заболявания на червата</h4><p>Наблюдава се при остри бактериални и вирусни ентерити, болест на Crohn, туберкулоза, болест на Whipple, амилоидоза и екстранодални лимфоми.</p><h4>Медикаментозна и химична малабсорбция</h4><p>Причинители могат да бъдат хлорамфеникол, неомицин, терамицин, пеницилин в комбинация със сулфонамиди, трипаранол, метотрексат и др.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Болест на Уипъл.</h2><br><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 52. Идиопатични заболявания на червата. Патогенетични нарушения. Морфологични прояви. Улцерозен колит.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 53. Болест на Крон – морфологични прояви.</h1><p><strong>Синоними:</strong> регионален ентерит, терминален илеит.</p><h2>Честота</h2><p>Заболяването се среща най-често при млади хора между <strong>20–30 години</strong>, но може да се наблюдава и при деца и възрастни.</p><h2>Етиология</h2><p>Етиологията не е напълно изяснена. Предполага се участие на имунологични механизми, реакции на свръхчувствителност, генетични фактори и имунен дефицит.</p><h2>Морфогенеза</h2><p>Основно значение има увреждането на <strong>лимфната тъкан и лимфните съдове</strong> на тънкото черво. Развиват се лимфостаза и силен оток, особено в субмукозата, последвани от лимфохистиоцитна хиперплазия, вторични улцерации и грануломатозно възпаление. С течение на времето настъпват <strong>фиброза </strong>и <strong>склероза </strong>на чревната стена.</p><h2>Локализация</h2><p>В около <strong>60%</strong> от случаите процесът засяга <strong>терминалния илеум</strong>. По-рядко се ангажират йеюнумът и дуоденумът. В част от случаите се засягат и други отдели на гастроинтестиналния тракт — колон, анус или стомах. Апендиксът се поразява рядко.</p><h2>Макроскопски</h2><p>Чревната стена е силно <strong>задебелена</strong>. По серозата се виждат дребни белезникави възелчета, наподобяващи туберкули. За болестта на Crohn е характерно <strong>сегментното („patchy“) засягане на червото</strong> — редуват се участъци от болна и относително <strong>запазена лигавица („skip lesions“)</strong>.<br>Лигавицата показва множество <strong>линеарни улцерации</strong>, между които остават острови оточна и инфилтрирана лигавица. Така се оформя характерният вид на <strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-02/text-editor-images/2026/05/1777748820243-image.png &quot;width=100%&quot;)\" id=\"note-1777748822810-4\">калдъръмена“ („паважна“/\"cobblestone\") лигавица</span></strong>.</p><p>В по-късните стадии настъпват фиброза и развитие на стриктури и стенози. При тежки случаи илеумът придобива вид на <strong>„лула“</strong> поради значително стеснение на лумена.</p><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-02/text-editor-images/2026/05/1777749162815-image.png &quot;width=100%&quot;)\" id=\"note-1777749168353-6\">Микроскопски</span></h2><p>Хистологичната картина е характерна и се отличава с <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-02/text-editor-images/2026/05/1777749526744-image.png &quot;width=100%&quot;)\" id=\"note-1777749528791-8\">трансмурално възпаление</span></strong>, обхващащо всички слоеве на чревната стена. В лигавицата се виждат язви, които често достигат до субмукозата, а понякога проникват и по-дълбоко. Около тях има възпалителен инфилтрат от левкоцити, макрофаги, лимфоцити и единични гигантски клетки.</p><p>Най-характерният белег са <strong><span class=\"editor-note\" data-note=\"„Едно от усложненията на трансмуралното възпаление при болест на Крон е образуването на **фистули**. Тук се вижда **фисура **, която се разпростира през мукозата в субмукозата към мускулния слой, което в крайна сметка ще оформи фистулен тракт. Фистулите могат да се образуват между чревни бримки, пикочния мехур и дори кожата. При засягане на дебелото черво често се наблюдават периректални фистули.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-02/text-editor-images/2026/05/1777749253938-image.png &quot;width=100%&quot;)\" id=\"note-1777749301069-7\">трансмуралните фисури</span></strong> — дълбоки цепковидни улцерации, започващи от лигавицата и проникващи през субмукозата, понякога до мускулния слой. Около тях се развива <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-02/text-editor-images/2026/05/1777749044350-image.png &quot;width=100%&quot;)\" id=\"note-1777749046120-5\">грануломатозно възпаление</span></strong> с епителоидни клетки, <strong>гигантски клетки тип </strong><strong>Langhans</strong> и лимфоцити. Грануломите наподобяват туберкулозни, но <strong>липсва казеозна некроза</strong>.</p><p>В запазената лигавица въсите са атрофични, криптите — разширени и деформирани. Чашковидните клетки намаляват, а клетките на Панет са хиперплазирали.</p><p>Субмукозата е силно оточна и задебелена. Наблюдават се дилатирани лимфни съдове, хиперплазирали лимфни фоликули и периваскуларна лимфоцитна инфилтрация. Мускуларис мукозе е хипертрофирал.</p><h2>Изход и усложнения</h2><p>Поради хроничния ход заболяването завършва с фиброза, склероза и стеноза на чревния лумен, което може да доведе до синдром на малабсорбция.</p><p>Фисурите и язвите могат да причинят перфорация, перитонит, сраствания и фистули между чревни бримки.</p><p>Около язвите могат да се развият <strong>диспластични промени</strong>, върху които по-често възниква <strong>карцином</strong>, поради което болестта на Crohn се приема за <strong>преканцероза</strong>.</p><h2>Диференциална диагноза</h2><p>При <strong>чревната туберкулоза</strong> промените обхващат циркулярно чревната стена, докато при Crohn улцерациите са предимно <strong>линеарни</strong> и разположени по надлъжната ос.</p><p><strong>Саркоидозата</strong> рядко засяга гастроинтестиналния тракт и обикновено се съчетава с изменения в белите дробове и лимфните възли.</p><p>От <strong>улцерозния колит</strong> болестта на Crohn се различава с <strong>трансмуралното (с фисури) и сегментно („skip lesions“) засягане</strong> на чревната стена. За разлика от това, при <strong>улцерозния колит</strong> възпалението е ограничено предимно в лигавицата и субмукозата, засягането е <strong>дифузно и континуално</strong>, почти винаги ангажира ректума и <strong>липсват грануломи</strong> (освен при руптура на крипти). </p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 54. Апендицити. Видове, морфологична характеристика.</h1><h2>Остър апендицит</h2><p>Това е изключително често заболяване, което се среща във всички възрасти, но най-често засяга млади хора.</p><h3>Морфогенеза</h3><p>Основно значение има <strong>ентералната бактериална автоинфекция</strong>. Най-чести причинители са <strong>Escherichia coli</strong>, ентерококи и β-хемолитични стрептококи.</p><p>Развитието на възпалението се благоприятства от застой в лумена на апендикса вследствие:</p><ul><li>нарушена перисталтика;</li><li>прегъване на апендикса;</li><li>стеркорални камъни;</li><li>паразити или чужди тела.</li></ul><p>Повишеното интралуменово налягане води до колапс на съдовете в стената с последващата исхемия и увреждане на лигавицата. През тези дефекти бактериите проникват в стената на апендикса. Първоначално възпалението е ограничено в лигавицата (<strong>повърхностен афект</strong>), а по-късно обхваща цялата стена и преминава във <strong>флегмонозно (гнойно) възпаление</strong>. Разпространението на гнойната инфекция се благоприятства от богатството на лимфни съдове в апендикса.</p><h3>Макроскопски</h3><p>Луменът на апендикса е изпълнен със стерколити или гной. Серозата е хиперемирана и често покрита с фибринозно-гноен или гноен налеп. Стената е оточна и задебелена. Лигавицата е хиперемирана и набъбнала, понякога с малки язви, а при тежки форми — с обширна некроза. При <strong>гангренозен апендицит</strong> стената има зеленикавочерен цвят и налепи.</p><h3>Микроскопски</h3><p>Картината е различна, в зависимост от вида на възпалителния процес.</p><p><strong>Остър (ранен) апендицит\n</strong>Това са най-ранните и леки промени в апендикса. Наблюдават се:</p><ul><li>кръвна стаза в капилярите и венулите;</li><li>оток и малки кръвоизливи в лигавицата;</li><li>сидерофаги;</li><li>перивазални струпвания на левкоцити (начална левкодиапедеза).</li></ul><p>По-късно, на фона на дисциркулаторните нарушения, особено в дисталните отдели на апендикса, в лигавицата се появяват огнища на гнойно възпаление с конусовидна форма. Към лумена се виждат повърхностни некрози на лигавицата.</p><p><strong>Остър гноен (флегмонозен) апендицит\n</strong></p><p>За около 24 часа левкоцитният инфилтрат обхваща цялата стена на апендикса. По серозата има фибринозен или фибринозно-гноен ексудат.</p><p>В стената могат да се формират малки абсцеси — <strong>апостематозен апендицит</strong>. При масивно разязвяване на лигавицата процесът се означава като <strong>флегмонозно-язвен апендицит</strong>.</p><p><strong>Гангренозен апендицит\n</strong></p><p>Лигавицата е почти напълно разрушена. Налице са масивни кръвоизливи и некроза, която може да обхване цялата стена и да достигне серозата, причинявайки перфорация.</p><p>Гнойната инфилтрация тотално пропива стената и може да премине към околните тъкани с развитие на:</p><ul><li><strong>периапендицит</strong>;</li><li><strong>перитифлит</strong>;</li><li>тромбоваскулит на съдовете в мезоапендикса.</li></ul><h3>Усложнения</h3><p>Най-важните усложнения са:</p><ul><li>перфорация с локален или дифузен перитонит;</li><li>периапендикуларен абсцес;</li><li>емпием на апендикса;</li><li>периапендицит и перитифлит;</li><li>пилефлебитни абсцеси в черния дроб;</li><li>септицемия или септикопиемия.</li></ul><p>При тежка деструкция може да настъпи <strong>самоампутация на апендикса</strong>.</p><h4>Диференциална диагноза</h4><p>Острият апендицит трябва да се различава от:</p><ul><li>мезентериален лимфаденит;</li><li>интраперитонеални кръвоизливи;</li><li>остър салпингит;</li><li>паразитни инфекции;</li><li>болест на Crohn;</li><li>Мекелов дивертикул;</li><li>фоликуларна лимфоидна хиперплазия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен апендицит</h2><p>Хроничният апендицит най-често се развива след прекаран остър апендицит. Постепенно възпалително-деструктивните промени се заместват от гранулационна, а след това от фиброзна и цикатрициална тъкан.</p><p>Развиват се:</p><ul><li>атрофия;</li><li>фиброза и склероза на стената;</li><li>облитерация на лумена;</li><li>сраствания с околните тъкани.</li></ul><h3>Макроскопски</h3><p>Апендиксът е изтънен, плътен, с редуциран или облитерирал лумен. Понякога има вид на фиброзна връв.</p><h3>Микроскопски</h3><p>Във всички слоеве на стената има мононуклеарна клетъчна инфилтрация, най-силно изразена субсерозно. Често се формират големи лимфни фоликули.</p><p>Лигавицата е атрофична, субмукозата — фиброзно разширена, а серозата — задебелена и склерозирала. Могат да се видят и огнища на липоматоза.</p><p>Появата на левкоцити и разязвявания е белег за обостряне на процеса.</p><p>Фиброзно-склеротичните промени могат да причинят облитерация на проксималния отдел на апендикса със задръжка на слузест секрет и кистично разширяване — <strong>мукоцеле </strong>на апендикса.</p><p>При руптура на мукоцелето слузта попада в коремната кухина и по перитонеума се развиват миксоматозни възелчета — <strong>псевдомиксома на перитонеума</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 55. Чревна непроходимост. Видове, морфологична характеристика.</h1><p>Нарушенията в пасажа на чревното съдържимо са два основни типа: <strong style=\"color: rgb(31, 41, 55)\">механичен илеус</strong> и <strong style=\"color: rgb(31, 41, 55)\">паралитичен илеус</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Механичен илеус</h2><p>Механичният илеус бива <strong>обтурационен</strong> и <strong>странгулационен</strong>.</p><h3>Обтурационен илеус</h3><p>Развива се при запушване на чревния лумен от процес в самото черво или при притискане отвън. Причини могат да бъдат <strong>тумори, безоари, жлъчни камъни, паразити, туберкулоза</strong> и др.</p><h3>Странгулационен илеус</h3><p>При него освен запушване на пасажа се притискат и <strong>съдовете и нервите на мезентериума</strong>, което води до исхемия и инфаркт на чревната стена.</p><p>Различават се няколко форми:</p><p><strong>1. Инкарцерация\n</strong>Представлява заклещване на чревна бримка в херниален сак или в чревни бидове (сраствания между чревните гънки). Може да стане внезапно или по-бавно и връщането на червото в първоначалното му положение е невъзможно.</p><p>Чревното съдържимо на инкарцерираните чревни бримки не може да премине, приводящият сегмент се раздува и се развиват <strong>miserere </strong>(повръщане на фекални маси), интоксикация и електролитни нарушения.</p><p>Впоследствие компресията на мезентериалните съдове от съдържимото се причинява <strong>хеморагичен инфаркт</strong> на чревната стена, повишена пропускливост и развитие на <strong>перитонит</strong>.</p><p><strong>2. Волвулус\n</strong>Най-често засяга <strong>тънкото черво</strong> или <strong>сигмата</strong>, които имат дълъг мезентериум. Червото се завърта 360°–540° около оста си заедно с мезентериума, при което се компресират съдовете и настъпва инфаркт на стената.</p><p>Честа причина е хроничният запек, особено при сигмален волвулус.</p><p><strong>3. Инвагинация\n</strong>По-честа е при деца, особено до 1-годишна възраст. При възрастни често е свързана с <strong>полипи</strong> или други доброкачествени тумори.</p><p>Проксималният чревен сегмент навлиза в дисталния под действие на перисталтиката. Най-често се засяга <strong>илео-цекалната област </strong>поради антиперисталтичните вълни. При напречен срез се вижда характерна „<strong>тройна чревна стена</strong>“. При инвагинацията се притискат съдовете на мезентериума на инвагинираните чревни гънки и те се инфарцират.</p><p>Трябва да се различава от <strong>агоналната инвагинация</strong>, при която липсват структурни промени в чревната стена.</p><h3>Макроскопски промени</h3><p>При всички форми на механичен илеус приводящият сегмент е силно <strong>раздут</strong> и изпълнен с фекални материи и газове. Странгулираният участък е тъмночервен, оточен и впоследствие <strong>хеморагично инфарциран</strong>.</p><p>Чревната стена става къслива, а в коремната кухина се натрупва <strong>кръвенисто-гноен ексудат</strong>. По серозата се наблюдават <strong>фибринозно-гнойни </strong>или <strong>гнойни </strong><strong>налепи</strong>, отговарящи на развилия се перитонит.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Паралитичен илеус</h2><p>Той се дължи на парализа на червата, при която се загубва тяхната моторика (перисталтичните движения) и настъпва т.н. динамична или спастична непроходимост. Най-често възниква при <strong>перитонит</strong>, след оперативна травма, интраабдоминален кръвоизлив или рефлекторно при други заболявания.</p><p>Паралитичен илеус може да настъпи и при нарушения в мезентериалното кръвоснабдяване — <strong>тромбоза</strong> или <strong>емболия</strong> на мезентериалните съдове. Това води до хеморагичен инфаркт, повишена пропускливост на стената и вторичен перитонит.</p><h3>Макроскопски промени</h3><p>Чревните бримки са силно раздути и изпълнени с течно съдържимо. Стената е къслива. В коремната кухина се открива различен по характер ексудат — гноен, фибринозен, гнойно-хеморагичен или фибринозно-гноен, а по серозата се виждат съответни налепи.</p><p>Хеморагичното инфарциране при механичния илеус често води до перитонит, поради което към механичната непроходимост се прибавя и <strong>паралитична компонента</strong>.</p><p>Най-честа причина за илеус е <strong>инкарцерацията на хернии </strong>(почти 50%), следвана от туморна обтурация и сраствания. По-редки са <strong>инвагинацията</strong> и <strong>волвулусът</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 56. Перитонити. Видове, морфологична характеристика.</h1><p>Перитонитът представлява <strong>възпаление на перитонеума</strong> и не е самостоятелно заболяване, а усложнение на други патологични процеси. Може да протече като <strong>остър</strong> или <strong>хроничен</strong> перитонит.</p><h2>Етиология</h2><p>Перитонитът възниква вследствие попадане на инфекция или дразнещи материи в перитонеалната кухина. Причинители могат да бъдат стрептококи, стафилококи, <strong>E. coli</strong>, пневмококи, гонококи, туберкулозни микобактерии и анаеробни бактерии.</p><p>Инфекцията достига перитонеума:</p><ul><li>от чревния лумен при повишена пропускливост или перфорация;</li><li>чрез пробив от съседни органи;</li><li>хематогенно от далечни огнища;</li><li>отвън — при травми и операции.</li></ul><p>Най-чест източник са заболяванията на стомаха, червата и апендикса. Перитонит се развива при:</p><ul><li>перфорация на язва или тумор;</li><li>разкъсване на чревна стена или разпад на оперативни шевове (<strong>стеркорален перитонит</strong>);</li><li>гноен апендицит, холецистит или аднексит;</li><li>повишена чревна пропускливост.</li></ul><p>Възможен е и <strong>асептичен (стерилен) перитонит</strong>, без бактериална инфекция:</p><ul><li>при излив на жлъчка (<strong>билиарен перитонит</strong>);</li><li>при кръвоизлив в коремната кухина;</li><li>при попадане на талк или хирургични материали;</li><li>при уремия и други токсични състояния.</li></ul><p>Перитонитът може да бъде <strong>ограничен</strong> или <strong>дифузен</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър перитонит</h2><h3>Макроскопски</h3><p>Според характера на възпалението остър перитонит бива <strong>серозен</strong>, <strong>серо-фибринозен</strong>, <strong>фибринозен </strong>или <strong>фибринозно-гноен</strong>.</p><h3>Дифузен перитонит</h3><p>Коремът е силно <strong>балониран </strong>поради масивен метеоризъм. Чревните бримки са дилатирани, изпълнени с газове и втечнено съдържимо. При перфорация или анаеробна инфекция може да има свободни газове и в коремната кухина.</p><p>Серозата на червата и париеталният перитонеум са помътнени, хиперемирани и покрити с фибринозни или гнойни налепи. При инфекция с <strong>E. coli</strong> гнойта има неприятна миризма.</p><p>Микроскопски се установяват десквамация на мезотела, съдова хиперемия, фибринозен или гноен ексудат и левкоцитна инфилтрация.</p><h3>Ограничен перитонит</h3><p>Развива се около локално възпалително огнище и често се ограничава от сраствания. Наблюдава се при апендицит, аднексит, перихолецистит и субфренични абсцеси.</p><p>Понякога гнойната колекция може да се дренира към черво и процесът да се самоограничи. При пробив в свободната коремна кухина обаче настъпва дифузен перитонит.</p><h3>Клиника и изход</h3><p>Клинично перитонитът протича като <strong>„остър корем“</strong>. При своевременно лечение ексудатът частично се резорбира и настъпва организация със сраствания.</p><p>Дифузният перитонит е тежко състояние, при което се развиват <strong>паралитичен илеус</strong>, интоксикация, електролитни нарушения и шок. Характерно е т.нар. <strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-02/text-editor-images/2026/05/1777751509256-image.png &quot;width=100%&quot;)\" id=\"note-1777751511325-9\">Хипократово лице</span>“</strong> — изострен нос, хлътнали очи, сивкава кожа и помътнени роговици.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен перитонит</h2><p>Хроничният перитонит най-често е изход от остър перитонит или се развива първично, особено при <strong>туберкулоза</strong>. Възпалението има продуктивен характер с развитие на фиброза и сраствания.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 57. Доброкачествени и злокачествени тумори на тънко и дебело черво.</h1><p><span style=\"color: rgb(88, 129, 87)\"><strong>Анатомия.</strong></span></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\"><span style=\"color: rgb(255, 192, 0)\">Общо за черен дроб.</span></h1><p><strong><span style=\"color: rgb(88, 129, 87)\"><span class=\"editor-note\" data-note=\"# Анатомия и хистология на черния дроб\nЧерният дроб е паренхимен орган с тегло около **1500 g**, разположен в дясното подребрие. Покрит е от **Глисонова капсула** и перитонеум.\nАнатомично се разделя на десен, ляв, квадратен и опашен (**caudatus**) дял. Според съдовото и жлъчното разклоняване се разграничават и **8 чернодробни сегмента**, всеки от които съдържа клонове на **v. portae**, **a. hepatica**, жлъчни и лимфни съдове и нерви.\n## Кръвоснабдяване\nЧерният дроб е един от най-кръвоснабдените органи — за минута през него преминават над **1500 ml кръв**. По-голямата част идва от **порталната вена**, а останалата — от **чернодробната артерия**.\nПорталната вена се формира от слезковата, горната и долната мезентериална и езофагеалните вени. След навлизането си в черния дроб тя се разклонява, а кръвта преминава през **синусоидите** и чрез централните вени се оттича към долната празна вена. Между порталната и кавалната система съществуват **портокавални анастомози**.\n# Хистологична структура\nОсновната структурна единица е **чернодробното делче (ацинус)**. Според Kiernan то има полиедрична форма и хексагонален вид на срез.\nВ периферията на делчето се разполагат **порталните пространства**, съдържащи клонове на **a. hepatica propria**, **v. portae**, жлъчни каналчета и лимфни съдове. Те са обвити от съединителна тъкан, произхождаща от Глисоновата капсула.\nВ центъра на делчето се намира **централната вена**. От нея радиерно към порталните пространства се подреждат **чернодробните гредички**, изградени от един ред **хепатоцити**.\n## Хепатоцити\nХепатоцитите са клетки с диаметър **15–30 μm** и кръгло ядро. В цитоплазмата им се съдържат всички основни клетъчни органели — митохондрии, ендоплазмен ретикулум, апарат на Голджи, лизозоми и др.\nВ тях могат да се открият:\n* анаболитни включвания — гликоген, липиди, белтъци;\n* катаболитни включвания — липофусцин, хемосидерин.\n## Чернодробни синусоиди\nМежду чернодробните гредички се намират **синусоидите**, по които тече смесена артериална и венозна кръв.\nТе са покрити от ендотелни клетки, **Kupffer**-ови клетки и pit-cells. Синусоидите нямат истинска базална мембрана, което позволява свободен обмен между кръвта и **пространството на Disse**.\nВ пространството на Disse се намират **Ito-клетките**, които натрупват липиди, синтезират медиатори на възпалението и могат да се трансформират в колаген-синтезиращи миофибробласти.\n## Жлъчни пътища\nЖлъчката се синтезира в хепатоцитите и се отделя в жлъчните каналчета, след което преминава към събирателните каналчета в порталните пространства. Те са покрити с **кубичен епител**.\n## Зони в чернодробното делче\nРазличават се:\n* периферна зона — около порталните пространства;\n* интермедиерна зона;\n* централна (центроацинозна) зона — около централната вена.\n## Функции\nВ черния дроб се осъществяват:\n* въглехидратна;\n* мастна;\n* белтъчна;\n* пигментна обмяна.\" id=\"note-1777829082137-5\" style=\"\">Анатомия</span>. <span class=\"editor-note\" data-note=\"# Чернодробна биопсия\nЧернодробната биопсия има важно значение в диагностиката на чернодробните заболявания. Използват се хирургична, пункционна (с игла на **Menghini**) и тънкоиглена пункционна биопсия.\nБиопсията е особено полезна при диагностика на:\n* дегенеративни процеси;\n* възпалителни заболявания;\n* тумори.\nОт биопсичния материал могат да се извършат рутинно хистологично, хистохимично, имунохистохимично и електронномикроскопско изследване.\" id=\"note-1777829087591-6\" style=\"\">Биопсия</span>.</span></strong></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Общи данни за процесите в черния дроб</h2><p>При изследване на материал от чернодробна биопсия се оценяват следните морфологични промени:</p><ul><li>дегенеративни промени;</li><li>некроза и възпаление;</li><li>фиброза;</li><li>холестаза;</li><li>съдови промени;</li><li>адаптация;</li><li>отлагане на пигменти;</li><li>пролиферация;</li><li>малигнена трансформация.</li></ul><p>Чернодробната биопсия има важно значение за поставяне на диагнозата и оценка на прогнозата. Фиброзата показва тежестта на увреждането и риска от развитие на цироза. Съдовите промени се оценяват чрез капиларизацията на синусоидите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Морфологичен отговор на черния дроб при увреждане</h2><p>Морфологичният отговор протича в три основни етапа:</p><ol><li>увреда — дегенерация и некроза;</li><li>възпалителна реакция;</li><li>възстановяване:</li><ul><li>пълно чрез регенерация;</li><li>непълно чрез фиброзиране и заздравяване.</li></ul></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Некроза</h3><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-03/text-editor-images/2026/05/1777829463785-image.png &quot;width=100%&quot;)\" id=\"note-1777829465601-10\">Телца на Councilman</span>\n</strong>Представляват единични апоптотични хепатоцити с:</p><ul><li>еозинофилна (ацидофилна) цитоплазма;</li><li>пикнотични или липсващи ядра.</li></ul><p>Наблюдават се често при вирусни хепатити.</p><p><strong>Фокални некрози</strong>\nЗагиват групи хепатоцити, около които се развива възпалителна реакция.\nМикроскопски:</p><ul><li>малки огнища на некроза;</li><li>възпалителни клетки около увредата;</li><li>могат да се формират неспецифични грануломи.</li></ul><p><strong>Мултифокални некрози\n</strong>Представляват множество малки огнища на некроза, разпръснати в чернодробния паренхим.</p><p>Микроскопски:</p><ul><li>множество некротични огнища;</li><li>загинали хепатоцити;</li><li>възпалителен инфилтрат около тях.</li></ul><p><strong>Зонални некрози\n</strong>Обхващат определени зони на чернодробното делче — зона 1, 2 или 3.\nНай-често се засяга:</p><ul><li><strong>зона 3 (центролобуларна)</strong> при токсични увреждания и хипоксия.</li></ul><p>Наблюдават се при:</p><ul><li>интоксикация с парацетамол;</li><li>токсични увреждания;</li><li>хипоксични състояния.</li></ul><p><strong>Мостови (bridging) некрози\n</strong>Некротичните участъци свързват:</p><ul><li>две портални пространства;</li><li>портално пространство с централна вена;</li><li>две централни вени.</li></ul><p>Срещат се най-често при тежки хепатити.</p><p><strong>Панлобуларни субмасивни некрози\n</strong>Обхващат и трите зони на чернодробното делче, но само в част от лобулите.</p><p><strong>Панлобуларни масивни некрози\n</strong>Обхващат всички зони във всички лобули.\nНаблюдават се при:</p><ul><li>тежки вирусни хепатити;</li><li>тежки токсични увреждания;</li><li>отравяне с гъби.</li></ul><p><strong>Интралобуларни перипортални („piece-meal“) некрози\n</strong>Разполагат се по границата между порталното пространство и чернодробния паренхим.\nХарактеризират се с:</p><ul><li>разрушаване на limiting plate;</li><li>възпалителен инфилтрат от лимфоцити;</li><li>имунно-медиирано увреждане на хепатоцитите.</li></ul><p>Срещат се най-често при <strong>хронични хепатити</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-03/text-editor-images/2026/05/1777829651177-image.png &quot;width=100%&quot;)\" id=\"note-1777829653049-11\">Модели на чернодробно увреждане</span></h2><ul><li><strong>Зонални некрози</strong> → токсични и хипоксични увреждания;</li><li><strong>Bridging некрози</strong> → тежки вирусни хепатити;</li><li><strong>Piece-meal некрози</strong> → имунно-медиирани хронични хепатити;</li><li><strong>Апоптоза</strong> → вирусни инфекции.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Вътреклетъчни включвания</h2><p>Наблюдават се различни интрацитоплазмени и интрануклеарни включвания:</p><ul><li>вирусни частици:</li><ul><li><strong>HBsAg</strong> → „матово стъкло“ хепатоцити;</li><li><strong>HBcAg</strong> → ядрени включвания;</li></ul><li><strong>телца на Mallory</strong> → увредени интермедиерни филаменти;</li><li>пептидни включвания:</li><ul><li>α1-антитрипсинови глобули;</li></ul><li>липиди;</li><li>гликоген;</li><li>липофусцин.</li></ul><h2>Пигментни натрупвания</h2><ul><li><strong>хемосидерин</strong> → доказва се с реакция на Perls;</li><li><strong>мед</strong> → доказва се с реакция на роданин.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Холестаза</h2><p>Представлява задръжка на жлъчка.</p><p>Може да бъде:</p><ul><li><strong>интрацелуларна</strong>;</li><li><strong>каналикуларна</strong>;</li><li><strong>дуктална</strong> — с жлъчни цилиндри.</li></ul><p>Среща се при:</p><ul><li>хепатити;</li><li>медикаментозни увреждания;</li><li>обструкция на жлъчните пътища.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Възпаление</h2><p>Възпалителният инфилтрат може да бъде:</p><ul><li>портален;</li><li>перипортален;</li><li>интралобуларен.</li></ul><p>Може да има:</p><ul><li>огнищен или дифузен характер;</li><li>неспецифично или специфично възпаление.</li></ul><p>Некрозата допълнително усилва възпалителната реакция.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Морфологични белези на регенерация</h2><ul><li>митози;</li><li>пролиферативни маркери (Ki-67);</li><li>полиплоидия на ядрата;</li><li>уголемени, полихромни ядра;</li><li>двуядрени хепатоцити.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Фиброза</h2><p>Фиброзата е важен показател за тежестта на чернодробното увреждане.</p><p>Видове:</p><ul><li><strong>портална фиброза</strong>;</li><li><strong>перипортална фиброза</strong>;</li><li><strong>септална фиброза</strong> — порто-портални, порто-централни и центро-централни септи;</li><li><strong>перисинусоидална фиброза</strong>;</li><li><strong>перивенозна фиброза (флебосклероза)</strong>;</li><li><strong>колапс на ретикуларната мрежа</strong>.</li></ul><p>Крайният стадий е <strong>цироза</strong> с нарушена архитектоника на черния дроб.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 58. Хепатити. Видове, морфологична характеристика.</h1><p><strong><span style=\"color: rgb(88, 129, 87)\"><span class=\"editor-note\" data-note=\"# Анатомия и хистология на черния дроб\nЧерният дроб е паренхимен орган с тегло около **1500 g**, разположен в дясното подребрие. Покрит е от **Глисонова капсула** и перитонеум.\nАнатомично се разделя на десен, ляв, квадратен и опашен (**caudatus**) дял. Според съдовото и жлъчното разклоняване се разграничават и **8 чернодробни сегмента**, всеки от които съдържа клонове на **v. portae**, **a. hepatica**, жлъчни и лимфни съдове и нерви.\n## Кръвоснабдяване\nЧерният дроб е един от най-кръвоснабдените органи — за минута през него преминават над **1500 ml кръв**. По-голямата част идва от **порталната вена**, а останалата — от **чернодробната артерия**.\nПорталната вена се формира от слезковата, горната и долната мезентериална и езофагеалните вени. След навлизането си в черния дроб тя се разклонява, а кръвта преминава през **синусоидите** и чрез централните вени се оттича към долната празна вена. Между порталната и кавалната система съществуват **портокавални анастомози**.\n# Хистологична структура\nОсновната структурна единица е **чернодробното делче (ацинус)**. Според Kiernan то има полиедрична форма и хексагонален вид на срез.\nВ периферията на делчето се разполагат **порталните пространства**, съдържащи клонове на **a. hepatica propria**, **v. portae**, жлъчни каналчета и лимфни съдове. Те са обвити от съединителна тъкан, произхождаща от Глисоновата капсула.\nВ центъра на делчето се намира **централната вена**. От нея радиерно към порталните пространства се подреждат **чернодробните гредички**, изградени от един ред **хепатоцити**.\n## Хепатоцити\nХепатоцитите са клетки с диаметър **15–30 μm** и кръгло ядро. В цитоплазмата им се съдържат всички основни клетъчни органели — митохондрии, ендоплазмен ретикулум, апарат на Голджи, лизозоми и др.\nВ тях могат да се открият:\n* анаболитни включвания — гликоген, липиди, белтъци;\n* катаболитни включвания — липофусцин, хемосидерин.\n## Чернодробни синусоиди\nМежду чернодробните гредички се намират **синусоидите**, по които тече смесена артериална и венозна кръв.\nТе са покрити от ендотелни клетки, **Kupffer**-ови клетки и pit-cells. Синусоидите нямат истинска базална мембрана, което позволява свободен обмен между кръвта и **пространството на Disse**.\nВ пространството на Disse се намират **Ito-клетките**, които натрупват липиди, синтезират медиатори на възпалението и могат да се трансформират в колаген-синтезиращи миофибробласти.\n## Жлъчни пътища\nЖлъчката се синтезира в хепатоцитите и се отделя в жлъчните каналчета, след което преминава към събирателните каналчета в порталните пространства. Те са покрити с **кубичен епител**.\n## Зони в чернодробното делче\nРазличават се:\n* периферна зона — около порталните пространства;\n* интермедиерна зона;\n* централна (центроацинозна) зона — около централната вена.\n## Функции\nВ черния дроб се осъществяват:\n* въглехидратна;\n* мастна;\n* белтъчна;\n* пигментна обмяна.\" id=\"note-1777828734162-3\">Анатомия</span>. <span class=\"editor-note\" data-note=\"# Чернодробна биопсия\nЧернодробната биопсия има важно значение в диагностиката на чернодробните заболявания. Използват се хирургична, пункционна (с игла на **Menghini**) и тънкоиглена пункционна биопсия.\nБиопсията е особено полезна при диагностика на:\n* дегенеративни процеси;\n* възпалителни заболявания;\n* тумори.\nОт биопсичния материал могат да се извършат рутинно хистологично, хистохимично, имунохистохимично и електронномикроскопско изследване.\" id=\"note-1777828739730-4\">Биопсия</span>.</span></strong></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p>дд</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\"><span style=\"color: rgb(112, 48, 160)\">Тема 59. Метаболитни чернодробни увреждания. Видове, морфологична характеристика.</span></h1><h2>Нарушения във водно-електролитния баланс на хепатоцита</h2><p>Различават се <strong>три степени на оводняване на хепатоцита</strong>:</p><h3>1. Оток на хепатоцита</h3><p>Най-леката степен на клетъчен оток.\n<strong>Макроскопски:  </strong>Черният дроб е леко увеличен, с леко заоблен преден ръб. Паренхимът е бледосивкаво-червен, с мековата консистенция и намалена еластичност.\n<strong>Микроскопски: </strong>Хепатоцитите са увеличени, с неясни граници. Цитоплазмата е финозърниста и бледо еозинофилна.\n<strong>Изход: </strong>Процесът е обратим след отстраняване на увреждащия фактор.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-03/text-editor-images/2026/05/1777829196711-image.png &quot;width=100%&quot;)\" id=\"note-1777830318451-12\">2. Вакуолна дегенерация</span></h3><p>По-тежка степен на клетъчен оток.\n<strong>Макроскопски: </strong>Черният дроб е по-увеличен по тегло и обем в сравнение с обикновения клетъчен оток.\n<strong>Микроскопски: </strong>В цитоплазмата на хепатоцитите се натрупват множество малки водни вакуоли, равномерно разпръснати и оптически празни при H&amp;E оцветяване.</p><h3>3. Балонна и хидропична дегенерация</h3><p>Най-тежката степен на оводняване на клетката.\n<strong>Етиология: </strong>Среща се при <strong>остър вирусен хепатит</strong> и <strong>хроничен активен хепатит</strong>.\n<strong>Макроскопски: </strong>Черният дроб е значително увеличен, мек и с рязко намалена еластичност.\n<strong>Микроскопски: </strong>Наблюдават се две фази:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-03/text-editor-images/2026/05/1777829321505-image.png &quot;width=100%&quot;)\" id=\"note-1777830364912-14\">балонна дегенерация</span></strong>;</li><li><strong>хидропична дегенерация</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-03/text-editor-images/2026/05/1777829350204-image.png &quot;width=100%&quot;)\" id=\"note-1777830336888-13\">Стеатоза на черния дроб</span></h2><p>Стеатозата представлява дегенеративен процес с <strong>натрупване на липиди в цитоплазмата на хепатоцитите</strong>.</p><h3>Етиология</h3><p>Причините включват:</p><ul><li><strong>токсични фактори</strong> – алкохол, медикаменти, пестициди;</li><li><strong>хипоксия</strong> – анемия, сърдечна и белодробна недостатъчност;</li><li><strong>ендокринни нарушения</strong> – диабет, синдром на Cushing, микседем;</li><li><strong>метаболитни фактори</strong> – затлъстяване, белтъчно недохранване;</li><li><strong>биологични причини</strong> – туберкулоза, синдром на малабсорбция и др.</li></ul><p>Най-честата причина е <strong>хроничният алкохолизъм</strong>.</p><h3>Морфогенеза</h3><p>Мастната дегенерация може да възникне чрез:</p><ul><li>повишен внос на масти в хепатоцитите;</li><li>липонеогенеза от въглехидрати;</li><li>усилена естерификация на мастните киселини;</li><li>нарушена β-оксидация;</li><li>намален синтез на апопротеини;</li><li>декомпозиция на липопротеидните комплекси.</li></ul><h3>Макроскопски</h3><p>Черният дроб е увеличен, понякога до <strong>2.5 kg</strong>. Капсулата е гладка и лъскава, консистенцията — мековата. На разрез паренхимът е жълто-кафяв до оранжев и наподобява <strong>„гъши черен дроб“</strong>.</p><h3>Микроскопски</h3><p>В цитоплазмата на хепатоцитите се виждат мастни вакуоли, които избутват ядрото към периферията. При H&amp;E оцветяване липидите изглеждат като оптически празни вакуоли.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Кумулативни заболявания на черния дроб</h2><p><strong>Синоними:</strong> тезауризмози, лизозомни болести, ензимопатии.\nТова са заболявания, при които поради нарушения в метаболизма различни вещества се натрупват свръхнормно в клетките.</p><h3>Порфирия</h3><p>Заболяване, свързано с нарушение в биосинтезата на <strong>порфирина и хема</strong>.</p><p><strong>Етиология:\n</strong>Обикновено е наследствено заболяване с <strong>автозомно-доминантно унаследяване</strong>. Изключение прави късната кожна порфирия, която е придобита.\nРазличават се:</p><ul><li><strong>чернодробна порфирия</strong>;</li><li><strong>еритропоетична порфирия</strong>.</li></ul><h3>Остра интермедиерна порфирия</h3><p>Засяга предимно черния дроб.</p><p><strong>Клиника:\n</strong>Характерни са:</p><ul><li>болезнени чревни колики;</li><li>констипация;</li><li>периферни неврологични и невропсихични симптоми.</li></ul><p><strong>Микроскопски:\n</strong>Наблюдават се:</p><ul><li><strong>стеатоза</strong>;</li><li><strong>хемосидероза</strong>;</li><li><strong>фиброза</strong> на чернодробния паренхим.</li></ul><p>При част от болните има перидуктална лимфоцитна инфилтрация, а в някои случаи се развива <strong>чернодробна цироза</strong>.</p><h3>Еритропоетична протопорфирия</h3><p><strong>Макроскопски:\n</strong>Чернодробният паренхим е с <strong>черен цвят</strong>.</p><p><strong>Микроскопски:\n</strong>Установява се натрупване на тъмнокафяв пигмент в:</p><ul><li>жлъчните каналчета;</li><li>съединителната тъкан;</li><li>Купферовите клетки.</li></ul><p>Може да се развият:</p><ul><li><strong>портална и перипортална фиброза</strong>;</li><li><strong>холелитиаза</strong>.</li></ul><p><strong>Изход:\n</strong>Често завършва с <strong>чернодробна цироза</strong> и смърт.</p><h3>Заболявания с нарушения във въглехидратната обмяна</h3><h4>Свръхнормно натрупване на гликоген в черния дроб</h4><p><strong>Синоним:</strong> гликогенози.\nТова са предимно <strong>автозомно-рецесивни наследствени заболявания</strong>, свързани с ензимен дефект.</p><p><strong>Клиника:\n</strong>Характерни са:</p><ul><li><strong>хепатомегалия</strong>;</li><li><strong>хипогликемия</strong>;</li><li>забавен растеж;</li><li>хиперлипидемия.</li></ul><p><strong>Микроскопски:\n</strong>В цитоплазмата на хепатоцитите се натрупва гликоген под формата на вакуоли. Те:</p><ul><li>се оцветяват червено с <strong>кармин по Best</strong>;</li><li>дават <strong>PAS-положителна реакция</strong>.</li></ul><p>При гликогеноза тип III и IV може да се развие <strong>чернодробна цироза</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Амилоидоза от обща патология</h2><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p>И още</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 60. Алкохолна болест на черния дроб. Видове, морфологична характеристика.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 61. Чернодробна цироза. Патогенеза, класификация, усложнения.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 62. Заболявания на интрахепаталните пътища. Видове, морфологична характеристика.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 63. Доброкачествени и злокачествени тумори на черния дроб – видове. Метастатични тумори.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 64. Възпалителни заболявания на жлъчния мехур и жлъчните пътища. Холелитиаза.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 65. Тумори на жлъчния мехур и жлъчните пътища.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 66. Остър и хроничен панкреатит. Етиология и патогенеза. Морфологични промени.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 67. Доброкачествени и злокачествени тумори на панкреаса.</h1><p>Начало</p><p><br></p><p><br></p><p><br></p><p><br></p><p style=\"text-align: center\"><br></p>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
